import com.kalynx.serverlessreviewtool.git.Git;
import com.kalynx.serverlessreviewtool.git.GitFactory;
import com.kalynx.serverlessreviewtool.git.ReviewItemLoader;
import com.kalynx.serverlessreviewtool.models.ReviewItem;

import java.util.List;

public class TestReviewLoading {
    public static void main(String[] args) {
        try {
            Git git = GitFactory.getInstance();
            ReviewItemLoader loader = new ReviewItemLoader(git);

            System.out.println("Loading reviews from java-backend-service...");
            List<ReviewItem> reviews = loader.loadReviewsFromRepository("java-backend-service")
                .get();

            System.out.println("\nFound " + reviews.size() + " reviews:");
            for (ReviewItem review : reviews) {
                System.out.println("  - Title: " + review.getTitle());
                System.out.println("    Author: " + review.getAuthor());
                System.out.println("    Repository: " + review.getRepository());
                System.out.println("    Status: " + review.getStatus());
                System.out.println();
            }

            System.out.println("Loading reviews from python-api-service...");
            reviews = loader.loadReviewsFromRepository("python-api-service")
                .get();

            System.out.println("\nFound " + reviews.size() + " reviews:");
            for (ReviewItem review : reviews) {
                System.out.println("  - Title: " + review.getTitle());
                System.out.println("    Author: " + review.getAuthor());
                System.out.println("    Repository: " + review.getRepository());
                System.out.println("    Status: " + review.getStatus());
                System.out.println();
            }

            System.out.println("Loading reviews from react-frontend-app...");
            reviews = loader.loadReviewsFromRepository("react-frontend-app")
                .get();

            System.out.println("\nFound " + reviews.size() + " reviews:");
            for (ReviewItem review : reviews) {
                System.out.println("  - Title: " + review.getTitle());
                System.out.println("    Author: " + review.getAuthor());
                System.out.println("    Repository: " + review.getRepository());
                System.out.println("    Status: " + review.getStatus());
                System.out.println();
            }

            System.out.println("✓ All reviews loaded successfully with no null values!");

        } catch (Exception e) {
            System.err.println("Error loading reviews: " + e.getMessage());
            e.printStackTrace();
        }
    }
}

import com.kalynx.serverlessreviewtool.git.Git;
import com.kalynx.serverlessreviewtool.git.GitFactory;
import com.kalynx.serverlessreviewtool.git.ReviewItemLoader;
import com.kalynx.serverlessreviewtool.models.ReviewItem;

import java.util.List;

public class VerifyReviews {
    public static void main(String[] args) {
        try {
            Git git = GitFactory.getInstance();
            ReviewItemLoader loader = new ReviewItemLoader(git);

            System.out.println("=== Java Backend Service ===");
            List<ReviewItem> javaReviews = loader.loadReviewsFromRepository("java-backend-service").get();
            System.out.println("Found " + javaReviews.size() + " reviews:");
            for (ReviewItem review : javaReviews) {
                System.out.println("  Title: " + review.getTitle());
                System.out.println("  Author: " + review.getAuthor());
                System.out.println("  Status: " + review.getStatus());
                System.out.println();
            }

            System.out.println("=== Python API Service ===");
            List<ReviewItem> pythonReviews = loader.loadReviewsFromRepository("python-api-service").get();
            System.out.println("Found " + pythonReviews.size() + " reviews:");
            for (ReviewItem review : pythonReviews) {
                System.out.println("  Title: " + review.getTitle());
                System.out.println("  Author: " + review.getAuthor());
                System.out.println("  Status: " + review.getStatus());
                System.out.println();
            }

            System.out.println("=== React Frontend App ===");
            List<ReviewItem> reactReviews = loader.loadReviewsFromRepository("react-frontend-app").get();
            System.out.println("Found " + reactReviews.size() + " reviews:");
            for (ReviewItem review : reactReviews) {
                System.out.println("  Title: " + review.getTitle());
                System.out.println("  Author: " + review.getAuthor());
                System.out.println("  Status: " + review.getStatus());
                System.out.println();
            }

            int totalReviews = javaReviews.size() + pythonReviews.size() + reactReviews.size();
            System.out.println("✓ SUCCESS: " + totalReviews + " reviews loaded with proper titles!");

        } catch (Exception e) {
            System.err.println("✗ ERROR: " + e.getMessage());
            e.printStackTrace();
        }
    }
}

package com.kalynx.serverlessreviewtool.git;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.Objects;
import java.util.stream.Stream;

/**
 * GitCommandNotes - Shell-level implementation of {@link GitNotesApi}.
 *
 * <p>All operations delegate to the {@code git} executable on the system PATH via
 * {@link ProcessBuilder}. The repository working directory is set for every command
 * so that callers can operate against multiple repositories without changing the JVM
 * working directory.
 *
 * <p>{@link #appendToStream} works in three steps:
 * <ol>
 *   <li>Loads the current stream content for the target ref if present.</li>
 *   <li>Appends one NDJSON line entry.</li>
 *   <li>Writes a new blob and points the stream ref at it via {@code git update-ref}.</li>
 * </ol>
 * This keeps each lane isolated while preserving full history inside the stream.
 */
public class GitCommandNotes implements GitNotesApi {

    private static final String FETCH_REFSPEC = "+" + NotesRef.wildcard() + ":" + NotesRef.wildcard();
    private static final String PUSH_REFSPEC = NotesRef.wildcard() + ":" + NotesRef.wildcard();
    private final RepositoryStore repositoryStore;

    /**
     * Creates an instance using the default local repository store root.
     */
    public GitCommandNotes() {
        this(new RepositoryStore(Paths.get(System.getProperty("user.home"), ".serverless-review-tool", "repositories")));
    }

    /**
     * Creates an instance using a custom repository store root path.
     *
     * @param storeRoot root directory used for local repository paths
     */
    public GitCommandNotes(Path storeRoot) {
        this(new RepositoryStore(storeRoot));
    }

    /**
     * Creates an instance with an explicit repository store implementation.
     *
     * @param repositoryStore repository store used to resolve repository paths
     */
    public GitCommandNotes(RepositoryStore repositoryStore) {
        this.repositoryStore = Objects.requireNonNull(repositoryStore, "repositoryStore");
    }

    /**
     * Returns a repository path from the configured repository store.
     *
     * @param repositoryKey unique key for the remote repository
     * @return absolute local path where the repository should be created
     * @throws GitException if the repository path cannot be prepared
     */
    public Path getOrCreateRepositoryPath(String repositoryKey) throws GitException {
        return repositoryStore.getOrCreateRepositoryPath(repositoryKey);
    }

    /**
     * Bootstraps notes for a repository key using the configured repository store.
     *
     * @param repositoryKey unique key for the remote repository
     * @param remote remote name
     * @param remoteUrl remote URL
     * @return absolute local path used for the repository
     * @throws GitException if bootstrap fails
     */
    public Path ensureNotesRepository(String repositoryKey, String remote, String remoteUrl) throws GitException {
        Path repoPath = repositoryStore.getOrCreateRepositoryPath(repositoryKey);
        this.cloneNotesRepository(repoPath, remote, remoteUrl);
        return repoPath;
    }

    /**
     * Removes a repository by key from the configured repository store.
     *
     * @param repositoryKey unique key for the remote repository
     * @throws GitException if deletion fails
     */
    public void removeRepository(String repositoryKey) throws GitException {
        removeRepository(repositoryStore.resolveRepositoryPath(repositoryKey));
    }

    /**
     * Clones only review notes refs into the target local repository path.
     *
     * @param repoPath repository root
     * @param remote remote name
     * @param remoteUrl remote URL
     * @throws GitException if clone/bootstrap commands fail
     */
    @Override
    public void cloneNotesRepository(Path repoPath, String remote, String remoteUrl) throws GitException {
        ensureDirectory(repoPath);
        ensureGitRepository(repoPath);
        ensureRemote(repoPath, remote, remoteUrl);
        fetchNotes(repoPath, remote);
    }

    /**
     * Removes a local repository directory used for notes operations.
     *
     * @param repoPath repository root
     * @throws GitException if deletion fails
     */
    @Override
    public void removeRepository(Path repoPath) throws GitException {
        if (!Files.exists(repoPath)) {
            return;
        }
        deleteDirectoryRecursively(repoPath);
    }

    /**
     * Appends one NDJSON entry to a stream ref.
     *
     * @param repoPath repository root
     * @param streamRef fully-qualified stream ref
     * @param entryJson one JSON object serialized as one NDJSON line
     * @throws GitException if stream read or write fails
     */
    @Override
    public void appendToStream(Path repoPath, String streamRef, String entryJson) throws GitException {
        String entryLine = normalizeEntryLine(entryJson);
        String existingContent = readStreamContent(repoPath, streamRef);
        String nextContent = appendEntry(existingContent, entryLine);
        String blobSha = createBlob(repoPath, nextContent);
        updateRef(repoPath, streamRef, blobSha);
    }

    /**
     * Reads all NDJSON lines from a stream ref.
     *
     * @param repoPath repository root
     * @param streamRef fully-qualified stream ref
     * @return ordered non-empty NDJSON lines
     * @throws GitException if stream read fails
     */
    @Override
    public List<String> readStreamEntries(Path repoPath, String streamRef) throws GitException {
        String content = readStreamContent(repoPath, streamRef);
        if (content.isEmpty()) {
            return List.of();
        }
        String[] lines = content.split("\\R");
        List<String> entries = new ArrayList<>();
        for (String line : lines) {
            if (!line.trim().isEmpty()) {
                entries.add(line);
            }
        }
        return entries;
    }

    /**
     * Fetches all review-note refs from the remote using union merge strategy.
     *
     * @param repoPath repository root
     * @param remote remote name
     * @throws GitException if fetch fails
     */
    @Override
    public void fetchNotes(Path repoPath, String remote) throws GitException {
        run(repoPath,
            List.of("git", "-c", "notes.mergeStrategy=union",
                    "fetch", remote, FETCH_REFSPEC));
    }

    /**
     * Pushes all local review-note refs to the remote.
     *
     * @param repoPath repository root
     * @param remote remote name
     * @throws GitException if push fails
     */
    @Override
    public void pushNotes(Path repoPath, String remote) throws GitException {
        run(repoPath, List.of("git", "push", remote, PUSH_REFSPEC));
    }

    /**
     * Creates a loose blob object in the repository from the supplied content.
     *
     * @param repoPath    repository root
     * @param content UTF-8 stream content to store as a blob
     * @return the 40-character SHA-1 of the newly created blob
     * @throws GitException if the hash-object command fails
     */
    private String createBlob(Path repoPath, String content) throws GitException {
        List<String> command = List.of("git", "hash-object", "-w", "--stdin");
        try {
            Process process = buildProcess(repoPath, command).start();
            writeStdin(process, content);
            CommandResult result = waitForResult(process);
            String sha = result.stdout.trim();
            int exitCode = process.waitFor();
            checkExitCode(command, exitCode, result.stderr);
            return sha;
        } catch (IOException | InterruptedException e) {
            if (e instanceof InterruptedException) {
                Thread.currentThread().interrupt();
            }
            throw new GitException("Failed to create blob: " + e.getMessage(), e);
        }
    }

    /**
     * Points the given fully-qualified ref at a specific object SHA.
     *
     * @param repoPath repository root
     * @param fullRef  the ref to create or overwrite
     * @param objectSha the target object SHA
     * @throws GitException if the update-ref command fails
     */
    private void updateRef(Path repoPath, String fullRef, String objectSha) throws GitException {
        run(repoPath, List.of("git", "update-ref", fullRef, objectSha));
    }

    /**
     * Runs a git command, waits for it to complete and throws if the exit code is non-zero.
     *
     * @param repoPath  repository root used as working directory
     * @param command   full command including {@code git} as the first element
     * @throws GitException if the process exits with a non-zero code or cannot be started
     */
    private void run(Path repoPath, List<String> command) throws GitException {
        try {
            Process process = buildProcess(repoPath, command).start();
            CommandResult result = waitForResult(process);
            int exitCode = process.waitFor();
            checkExitCode(command, exitCode, result.stderr);
        } catch (IOException | InterruptedException e) {
            if (e instanceof InterruptedException) {
                Thread.currentThread().interrupt();
            }
            throw new GitException("Failed to execute " + commandName(command) + ": " + e.getMessage(), e);
        }
    }

    private String runForStdout(Path repoPath, List<String> command) throws GitException {
        try {
            Process process = buildProcess(repoPath, command).start();
            CommandResult result = waitForResult(process);
            int exitCode = process.waitFor();
            checkExitCode(command, exitCode, result.stderr);
            return result.stdout;
        } catch (IOException | InterruptedException e) {
            if (e instanceof InterruptedException) {
                Thread.currentThread().interrupt();
            }
            throw new GitException("Failed to execute " + commandName(command) + ": " + e.getMessage(), e);
        }
    }

    private boolean refExists(Path repoPath, String ref) throws GitException {
        List<String> command = List.of("git", "show-ref", "--verify", "--quiet", ref);
        try {
            Process process = buildProcess(repoPath, command).start();
            CommandResult result = waitForResult(process);
            int exitCode = process.waitFor();
            if (exitCode == 0) {
                return true;
            }
            if (exitCode == 1) {
                return false;
            }
            throw new GitException(
                    "git " + commandName(command) + " failed (exit " + exitCode + "): " + result.stderr.trim(),
                    exitCode);
        } catch (IOException | InterruptedException e) {
            if (e instanceof InterruptedException) {
                Thread.currentThread().interrupt();
            }
            throw new GitException("Failed to execute " + commandName(command) + ": " + e.getMessage(), e);
        }
    }

    private String readStreamContent(Path repoPath, String streamRef) throws GitException {
        if (!refExists(repoPath, streamRef)) {
            return "";
        }
        return runForStdout(repoPath, List.of("git", "cat-file", "-p", streamRef));
    }

    private String appendEntry(String existingContent, String entryLine) {
        if (existingContent.isEmpty()) {
            return entryLine + "\n";
        }
        if (existingContent.endsWith("\n")) {
            return existingContent + entryLine + "\n";
        }
        return existingContent + "\n" + entryLine + "\n";
    }

    private String normalizeEntryLine(String entryJson) throws GitException {
        String normalized = entryJson.replace("\r", "").replace("\n", "").trim();
        if (normalized.isEmpty()) {
            throw new GitException("Stream entry cannot be empty", -1);
        }
        return normalized;
    }

    private void ensureDirectory(Path repoPath) throws GitException {
        try {
            Files.createDirectories(repoPath);
        } catch (IOException e) {
            throw new GitException("Failed to create repository directory: " + e.getMessage(), e);
        }
    }

    private void ensureGitRepository(Path repoPath) throws GitException {
        if (Files.isDirectory(repoPath.resolve(".git"))) {
            return;
        }
        run(repoPath, List.of("git", "init"));
    }

    private void ensureRemote(Path repoPath, String remote, String remoteUrl) throws GitException {
        if (hasRemote(repoPath, remote)) {
            run(repoPath, List.of("git", "remote", "set-url", remote, remoteUrl));
            return;
        }
        run(repoPath, List.of("git", "remote", "add", remote, remoteUrl));
    }

    private boolean hasRemote(Path repoPath, String remote) throws GitException {
        String remotes = runForStdout(repoPath, List.of("git", "remote"));
        String[] lines = remotes.split("\\R");
        for (String line : lines) {
            if (line.trim().equals(remote)) {
                return true;
            }
        }
        return false;
    }

    private void deleteDirectoryRecursively(Path repoPath) throws GitException {
        try (Stream<Path> paths = Files.walk(repoPath)) {
            paths.sorted(Comparator.reverseOrder()).forEach(path -> {
                try {
                    Files.deleteIfExists(path);
                } catch (IOException e) {
                    throw new RuntimeException(e);
                }
            });
        } catch (RuntimeException e) {
            if (e.getCause() instanceof IOException) {
                throw new GitException("Failed to remove repository: " + e.getCause().getMessage(), e.getCause());
            }
            throw e;
        } catch (IOException e) {
            throw new GitException("Failed to remove repository: " + e.getMessage(), e);
        }
    }

    private ProcessBuilder buildProcess(Path repoPath, List<String> command) {
        ProcessBuilder pb = new ProcessBuilder(command);
        pb.directory(repoPath.toFile());
        pb.redirectErrorStream(false);
        return pb;
    }

    private void writeStdin(Process process, String content) throws IOException {
        try (OutputStream stdin = process.getOutputStream()) {
            stdin.write(content.getBytes(StandardCharsets.UTF_8));
        }
    }

    private CommandResult waitForResult(Process process) throws IOException {
        String stdout = readStream(new BufferedReader(
                new InputStreamReader(process.getInputStream(), StandardCharsets.UTF_8)));
        String stderr = readStream(new BufferedReader(
                new InputStreamReader(process.getErrorStream(), StandardCharsets.UTF_8)));
        return new CommandResult(stdout, stderr);
    }

    private String readStream(BufferedReader reader) throws IOException {
        StringBuilder sb = new StringBuilder();
        String line;
        while ((line = reader.readLine()) != null) {
            sb.append(line).append("\n");
        }
        return sb.toString();
    }

    private void checkExitCode(List<String> command, int exitCode, String output) throws GitException {
        if (exitCode != 0) {
            throw new GitException(
                    "git " + commandName(command) + " failed (exit " + exitCode + "): " + output.trim(),
                    exitCode);
        }
    }

    private String commandName(List<String> command) {
        return command.size() > 1 ? command.get(1) : command.get(0);
    }

    private static class CommandResult {
        private final String stdout;
        private final String stderr;

        private CommandResult(String stdout, String stderr) {
            this.stdout = stdout;
            this.stderr = stderr;
        }
    }
}

package com.kalynx.serverlessreviewtool.git;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.nio.charset.StandardCharsets;
import java.nio.file.Path;
import java.util.List;

/**
 * GitProcess - Utility for running git commands as external processes.
 *
 * <p>All methods operate relative to the provided repository path so that
 * multiple repositories can be managed concurrently without changing the JVM
 * working directory.
 */
class GitProcess {

    private GitProcess() {
    }

    /**
     * Runs a git command and waits for completion, discarding stdout.
     *
     * @param repoPath absolute path used as the working directory
     * @param command  full command list with {@code git} as the first element
     * @throws GitException if the process exits with a non-zero code or cannot start
     */
    static void run(Path repoPath, List<String> command) throws GitException {
        try {
            Process process = build(repoPath, command).start();
            Result result = await(process);
            checkExitCode(command, process.waitFor(), result.stderr);
        } catch (IOException | InterruptedException e) {
            handleProcessException(e, command);
        }
    }

    /**
     * Runs a git command and returns its stdout output.
     *
     * @param repoPath absolute path used as the working directory
     * @param command  full command list with {@code git} as the first element
     * @return stdout content as a string
     * @throws GitException if the process exits with a non-zero code or cannot start
     */
    static String runForStdout(Path repoPath, List<String> command) throws GitException {
        try {
            Process process = build(repoPath, command).start();
            Result result = await(process);
            checkExitCode(command, process.waitFor(), result.stderr);
            return result.stdout;
        } catch (IOException | InterruptedException e) {
            handleProcessException(e, command);
            return "";
        }
    }

    /**
     * Runs a git command and returns the exit code without throwing on failure.
     *
     * @param repoPath absolute path used as the working directory
     * @param command  full command list with {@code git} as the first element
     * @return the process exit code
     * @throws GitException if the process cannot start
     */
    static int runForExitCode(Path repoPath, List<String> command) throws GitException {
        try {
            Process process = build(repoPath, command).start();
            await(process);
            return process.waitFor();
        } catch (IOException | InterruptedException e) {
            handleProcessException(e, command);
            return -1;
        }
    }

    /**
     * Writes content to the stdin of a running process.
     *
     * @param process the target process
     * @param content UTF-8 content to write
     * @throws IOException if writing fails
     */
    static void writeStdin(Process process, String content) throws IOException {
        try (OutputStream stdin = process.getOutputStream()) {
            stdin.write(content.getBytes(StandardCharsets.UTF_8));
        }
    }

    /**
     * Starts a process for a git command without waiting for completion.
     *
     * @param repoPath absolute path used as the working directory
     * @param command  full command list
     * @return the started process
     * @throws IOException if the process cannot be started
     */
    static Process start(Path repoPath, List<String> command) throws IOException {
        return build(repoPath, command).start();
    }

    /**
     * Reads stdout and stderr from the process and returns them as a result.
     *
     * @param process the process to read from
     * @return a result containing stdout and stderr content
     * @throws IOException if reading fails
     */
    static Result await(Process process) throws IOException {
        String stdout = readStream(new BufferedReader(
                new InputStreamReader(process.getInputStream(), StandardCharsets.UTF_8)));
        String stderr = readStream(new BufferedReader(
                new InputStreamReader(process.getErrorStream(), StandardCharsets.UTF_8)));
        return new Result(stdout, stderr);
    }

    /**
     * Throws a {@link GitException} if the exit code is non-zero.
     *
     * @param command  the command that was run
     * @param exitCode the process exit code
     * @param output   stderr output to include in the exception message
     * @throws GitException if exitCode is not zero
     */
    static void checkExitCode(List<String> command, int exitCode, String output) throws GitException {
        if (exitCode != 0) {
            throw new GitException(
                    "git " + name(command) + " failed (exit " + exitCode + "): " + output.trim(),
                    exitCode);
        }
    }

    /**
     * Returns the displayable command name for use in error messages.
     *
     * @param command full command list
     * @return subcommand name or the first element if the list has only one entry
     */
    static String name(List<String> command) {
        return command.size() > 1 ? command.get(1) : command.get(0);
    }

    private static ProcessBuilder build(Path repoPath, List<String> command) {
        ProcessBuilder pb = new ProcessBuilder(command);
        pb.directory(repoPath.toFile());
        pb.redirectErrorStream(false);
        return pb;
    }

    private static String readStream(BufferedReader reader) throws IOException {
        StringBuilder sb = new StringBuilder();
        String line;
        while ((line = reader.readLine()) != null) {
            sb.append(line).append("\n");
        }
        return sb.toString();
    }

    private static void handleProcessException(Exception e, List<String> command) throws GitException {
        if (e instanceof InterruptedException) {
            Thread.currentThread().interrupt();
        }
        throw new GitException("Failed to execute " + name(List.of("git", name(List.copyOf(command)))) + ": " + e.getMessage(), e);
    }

    /**
     * Holds the stdout and stderr output captured from a process.
     */
    static class Result {
        final String stdout;
        final String stderr;

        Result(String stdout, String stderr) {
            this.stdout = stdout;
            this.stderr = stderr;
        }
    }
}

package com.kalynx.serverlessreviewtool.managers;

import com.kalynx.serverlessreviewtool.git.Git;
import com.kalynx.serverlessreviewtool.models.Commit;
import com.kalynx.serverlessreviewtool.models.FileChangeType;
import com.kalynx.serverlessreviewtool.models.ReviewFile;
import com.kalynx.serverlessreviewtool.ui.models.mainpanels.reviewpanel.CodeViewerModel;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.CompletableFuture;

/**
 * FileDiffManager manages loading file diffs and content for code review.
 * Handles async operations for loading commits, changed files, and diff content.
 * Updates CodeViewerModel which triggers UI updates.
 */
public class FileDiffManager {
    private static final Logger logger = LoggerFactory.getLogger(FileDiffManager.class);

    private final Git git;
    private final CodeViewerModel codeViewerModel;

    public FileDiffManager(Git git, CodeViewerModel codeViewerModel) {
        this.git = git;
        this.codeViewerModel = codeViewerModel;
    }

    /**
     * Loads commits for a review from the specified repository and branch.
     * Updates the model with available commits and sets initial start/end commit range.
     *
     * @param repositoryName name of the repository
     * @param branch branch name to load commits from
     * @param maxCommits maximum number of commits to load
     * @return future that completes when commits are loaded
     */
    public CompletableFuture<Void> loadCommitsForReview(String repositoryName, String branch, int maxCommits) {
        logger.info("Loading commits for repository: {}, branch: {}, max: {}", repositoryName, branch, maxCommits);

        return git.listCommits(repositoryName, branch, maxCommits)
            .thenApply(this::parseCommits)
            .thenAccept(commits -> {
                logger.info("Loaded {} commits", commits.size());
                codeViewerModel.setAvailableCommits(commits);

                if (!commits.isEmpty()) {
                    int startIndex = Math.min(1, commits.size() - 1);
                    Commit startCommit = commits.get(startIndex);
                    Commit endCommit = commits.get(0);

                    logger.info("Setting initial commit range: start={}, end={}",
                        startCommit.getShortHash(), endCommit.getShortHash());

                    codeViewerModel.setCommitRange(startCommit, endCommit);
                } else {
                    logger.warn("No commits found for repository: {}, branch: {}", repositoryName, branch);
                }
            })
            .exceptionally(error -> {
                logger.error("Failed to load commits: {}", error.getMessage(), error);
                codeViewerModel.setAvailableCommits(new ArrayList<>());
                return null;
            });
    }

    public CompletableFuture<Void> loadFilesForReview(String repositoryName, String baseBranch, String reviewBranch) {
        logger.info("Loading all files for review: repository={}, base={}, review={}",
            repositoryName, baseBranch, reviewBranch);

        return git.listChangedFiles(repositoryName, baseBranch, reviewBranch)
            .thenApply(changedFiles -> parseChangedFiles(changedFiles, repositoryName))
            .thenAccept(codeViewerModel::setAvailableFiles)
            .exceptionally(error -> {
                logger.error("Failed to load files for review: {}", error.getMessage(), error);
                codeViewerModel.setAvailableFiles(new ArrayList<>());
                return null;
            });
    }

    /**
     * Loads the list of files changed between two commits.
     * Updates the model with available files.
     *
     * @param repositoryName name of the repository
     * @param startCommit starting commit for comparison
     * @param endCommit ending commit for comparison
     * @return future that completes when files are loaded
     */
    public CompletableFuture<Void> loadChangedFiles(String repositoryName, Commit startCommit, Commit endCommit) {
        if (startCommit == null || endCommit == null) {
            codeViewerModel.setAvailableFiles(new ArrayList<>());
            return CompletableFuture.completedFuture(null);
        }

        logger.info("Loading changed files from {} to {}", startCommit.getShortHash(), endCommit.getShortHash());

        return git.listChangedFiles(repositoryName, startCommit.getHash(), endCommit.getHash())
            .thenApply(changedFiles -> {
                logger.debug("Got {} changed file lines from git", changedFiles.size());
                if (!changedFiles.isEmpty()) {
                    logger.debug("First few lines: {}", changedFiles.subList(0, Math.min(3, changedFiles.size())));
                }
                return parseChangedFiles(changedFiles, repositoryName);
            })
            .thenAccept(codeViewerModel::setAvailableFiles)
            .exceptionally(error -> {
                String errorMessage = error.getMessage();
                if (errorMessage != null && errorMessage.contains("bad object")) {
                    logger.error("Failed to load changed files - commit not found in local repository. " +
                                "Repository may need to be synced. Start: {}, End: {}",
                                startCommit.getShortHash(), endCommit.getShortHash(), error);
                } else {
                    logger.error("Failed to load changed files: {}", errorMessage, error);
                }
                codeViewerModel.setAvailableFiles(new ArrayList<>());
                return null;
            });
    }

    /**
     * Loads diff content for a specific file between two commits.
     * Loads both side-by-side content (left/right) and unified diff format.
     * Updates the model with file content.
     * Handles ADDED and DELETED files gracefully with appropriate placeholder messages.
     *
     * @param repositoryName name of the repository
     * @param file file to load diff for
     * @param startCommit starting commit for comparison
     * @param endCommit ending commit for comparison
     * @return future that completes when diff is loaded
     */
    public CompletableFuture<Void> loadDiffForFile(String repositoryName, ReviewFile file,
                                                     Commit startCommit, Commit endCommit) {
        if (file == null || startCommit == null || endCommit == null) {
            return CompletableFuture.completedFuture(null);
        }

        // For ADDED files, left side doesn't exist
        CompletableFuture<String> leftContentFuture;
        if (file.getChangeType() == FileChangeType.ADDED) {
            leftContentFuture = CompletableFuture.completedFuture(
                "// File does not exist in commit " + startCommit.getShortHash() + "\n" +
                "// This file was added in commit " + endCommit.getShortHash());
        } else {
            leftContentFuture = loadFileContent(repositoryName, file.getPath(), startCommit.getHash(), file);
        }

        // For DELETED files, right side doesn't exist
        CompletableFuture<String> rightContentFuture;
        if (file.getChangeType() == FileChangeType.DELETED) {
            rightContentFuture = CompletableFuture.completedFuture(
                "// File was deleted in commit " + endCommit.getShortHash() + "\n" +
                "// This file existed in commit " + startCommit.getShortHash());
        } else {
            rightContentFuture = loadFileContent(repositoryName, file.getPath(), endCommit.getHash(), file);
        }

        CompletableFuture<String> unifiedDiffFuture = loadUnifiedDiff(repositoryName,
            file.getPath(), startCommit.getHash(), endCommit.getHash());

        return CompletableFuture.allOf(leftContentFuture, rightContentFuture, unifiedDiffFuture)
            .thenAccept(ignored -> {
                String leftContent = leftContentFuture.join();
                String rightContent = rightContentFuture.join();
                String unifiedDiff = unifiedDiffFuture.join();

                codeViewerModel.setLeftContent(leftContent);
                codeViewerModel.setRightContent(rightContent);
                codeViewerModel.setUnifiedDiffContent(unifiedDiff);
            })
            .exceptionally(error -> {
                logger.error("Failed to load diff for file {}: {}", file.getPath(), error.getMessage());
                codeViewerModel.setLeftContent("// Error loading content: " + error.getMessage());
                codeViewerModel.setRightContent("// Error loading content: " + error.getMessage());
                codeViewerModel.setUnifiedDiffContent("// Error loading diff: " + error.getMessage());
                return null;
            });
    }

    /**
     * Refreshes the current view by reloading changed files and the currently selected file's diff.
     * Used when user clicks the refresh button.
     *
     * @param repositoryName name of the repository
     * @return future that completes when refresh is done
     */
    public CompletableFuture<Void> refreshCurrentView(String repositoryName) {
        Commit startCommit = codeViewerModel.startCommit.getValue();
        Commit endCommit = codeViewerModel.endCommit.getValue();
        ReviewFile currentFile = codeViewerModel.selectedFile.getValue();

        if (startCommit == null || endCommit == null) {
            return CompletableFuture.completedFuture(null);
        }

        CompletableFuture<Void> filesRefresh = loadChangedFiles(repositoryName, startCommit, endCommit);

        if (currentFile != null) {
            CompletableFuture<Void> diffRefresh = loadDiffForFile(repositoryName, currentFile,
                startCommit, endCommit);
            return CompletableFuture.allOf(filesRefresh, diffRefresh);
        }

        return filesRefresh;
    }

    private CompletableFuture<String> loadFileContent(String repositoryName, String filePath,
                                                       String commitHash, ReviewFile file) {
        return git.executeAsync(repositoryName, "show", commitHash + ":" + filePath)
            .exceptionally(error -> {
                String errorMsg = error.getMessage();

                // Handle cases where file doesn't exist in this commit
                if (errorMsg != null && (errorMsg.contains("does not exist") ||
                                        errorMsg.contains("not in") ||
                                        errorMsg.contains("path") && errorMsg.contains("exists on disk"))) {

                    if (file.getChangeType() == FileChangeType.ADDED) {
                        return "// File does not exist in this commit\n" +
                               "// File: " + filePath + "\n" +
                               "// This file was added in a later commit";
                    } else if (file.getChangeType() == FileChangeType.DELETED) {
                        return "// File was deleted in a later commit\n" +
                               "// File: " + filePath + "\n" +
                               "// This file existed in an earlier commit";
                    } else {
                        return "// File not available in commit " + commitHash.substring(0, 8) + "\n" +
                               "// File: " + filePath;
                    }
                }

                // Other errors
                logger.warn("Failed to load file content for {} at {}: {}",
                           filePath, commitHash, errorMsg);
                return "// Error loading file content\n" +
                       "// File: " + filePath + "\n" +
                       "// Error: " + errorMsg;
            });
    }

    private CompletableFuture<String> loadUnifiedDiff(String repositoryName, String filePath,
                                                        String fromCommit, String toCommit) {
        return git.executeAsync(repositoryName, "diff", fromCommit, toCommit, "--", filePath)
            .exceptionally(error -> {
                String errorMsg = error.getMessage();
                logger.warn("Failed to generate unified diff for {}: {}", filePath, errorMsg);

                // Return a descriptive message for the diff pane
                return "# Unable to generate diff\n" +
                       "# File: " + filePath + "\n" +
                       "# Error: " + errorMsg;
            });
    }

    private List<Commit> parseCommits(List<String> commitStrings) {
        List<Commit> commits = new ArrayList<>();
        for (String commitString : commitStrings) {
            try {
                String[] parts = commitString.split("\\|", 4);
                if (parts.length >= 4) {
                    commits.add(new Commit(parts[0], parts[3], parts[1], parts[2]));
                } else {
                    logger.warn("Skipping malformed commit line: '{}' (only {} parts)", commitString, parts.length);
                }
            } catch (Exception e) {
                logger.error("Error parsing commit line '{}': {}", commitString, e.getMessage(), e);
            }
        }
        return commits;
    }

    private List<ReviewFile> parseChangedFiles(List<String> changedFileStrings, String repositoryName) {
        List<ReviewFile> files = new ArrayList<>();
        for (String fileString : changedFileStrings) {
            try {
                String trimmed = fileString.trim();
                if (trimmed.isEmpty()) {
                    continue;
                }

                String[] parts = trimmed.split("\\s+", 2);
                if (parts.length >= 2) {
                    String status = parts[0];
                    String path = parts[1];
                    FileChangeType changeType = parseFileChangeType(status);
                    files.add(new ReviewFile(path, repositoryName, changeType));
                } else {
                    logger.warn("Skipping malformed changed file line: '{}' (only {} parts)", trimmed, parts.length);
                }
            } catch (Exception e) {
                logger.error("Error parsing changed file line '{}': {}", fileString, e.getMessage(), e);
            }
        }
        return files;
    }

    private FileChangeType parseFileChangeType(String status) {
        if (status == null || status.isEmpty()) {
            logger.warn("Empty or null status, defaulting to MODIFIED");
            return FileChangeType.MODIFIED;
        }
        return switch (status.toUpperCase().charAt(0)) {
            case 'A' -> FileChangeType.ADDED;
            case 'M' -> FileChangeType.MODIFIED;
            case 'D' -> FileChangeType.DELETED;
            case 'R' -> FileChangeType.RENAMED;
            default -> FileChangeType.MODIFIED;
        };
    }
}

package com.kalynx.serverlessreviewtool.managers;

import com.kalynx.serverlessreviewtool.git.Git;
import com.kalynx.serverlessreviewtool.models.Commit;
import com.kalynx.serverlessreviewtool.models.FileChangeType;
import com.kalynx.serverlessreviewtool.models.ReviewFile;
import com.kalynx.serverlessreviewtool.ui.models.mainpanels.reviewpanel.CodeViewerModel;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.CompletableFuture;

/**
 * FileDiffManager manages loading file diffs and content for code review.
 * Handles async operations for loading commits, changed files, and diff content.
 * Updates CodeViewerModel which triggers UI updates.
 */
public class FileDiffManager {
    private static final Logger logger = LoggerFactory.getLogger(FileDiffManager.class);

    private final Git git;
    private final CodeViewerModel codeViewerModel;

    public FileDiffManager(Git git, CodeViewerModel codeViewerModel) {
        this.git = git;
        this.codeViewerModel = codeViewerModel;
    }

    /**
     * Loads commits for a review from the specified repository and branch.
     * Updates the model with available commits and sets initial start/end commit range.
     *
     * @param repositoryName name of the repository
     * @param branch branch name to load commits from
     * @param maxCommits maximum number of commits to load
     * @return future that completes when commits are loaded
     */
    public CompletableFuture<Void> loadCommitsForReview(String repositoryName, String branch, int maxCommits) {
        logger.info("Loading commits for repository: {}, branch: {}, max: {}", repositoryName, branch, maxCommits);

        return git.listCommits(repositoryName, branch, maxCommits)
            .thenApply(this::parseCommits)
            .thenAccept(commits -> {
                logger.info("Loaded {} commits", commits.size());
                codeViewerModel.setAvailableCommits(commits);

                if (!commits.isEmpty()) {
                    int startIndex = Math.min(1, commits.size() - 1);
                    Commit startCommit = commits.get(startIndex);
                    Commit endCommit = commits.get(0);

                    logger.info("Setting initial commit range: start={}, end={}",
                        startCommit.getShortHash(), endCommit.getShortHash());

                    codeViewerModel.setCommitRange(startCommit, endCommit);
                } else {
                    logger.warn("No commits found for repository: {}, branch: {}", repositoryName, branch);
                }
            })
            .exceptionally(error -> {
                logger.error("Failed to load commits: {}", error.getMessage(), error);
                codeViewerModel.setAvailableCommits(new ArrayList<>());
                return null;
            });
    }

    public CompletableFuture<Void> loadFilesForReview(String repositoryName, String baseBranch, String reviewBranch) {
        logger.info("Loading all files for review: repository={}, base={}, review={}",
            repositoryName, baseBranch, reviewBranch);

        return git.listChangedFiles(repositoryName, baseBranch, reviewBranch)
            .thenApply(changedFiles -> parseChangedFiles(changedFiles, repositoryName))
            .thenAccept(codeViewerModel::setAvailableFiles)
            .exceptionally(error -> {
                logger.error("Failed to load files for review: {}", error.getMessage(), error);
                codeViewerModel.setAvailableFiles(new ArrayList<>());
                return null;
            });
    }

    /**
     * Loads the list of files changed between two commits.
     * Updates the model with available files.
     *
     * @param repositoryName name of the repository
     * @param startCommit starting commit for comparison
     * @param endCommit ending commit for comparison
     * @return future that completes when files are loaded
     */
    public CompletableFuture<Void> loadChangedFiles(String repositoryName, Commit startCommit, Commit endCommit) {
        if (startCommit == null || endCommit == null) {
            codeViewerModel.setAvailableFiles(new ArrayList<>());
            return CompletableFuture.completedFuture(null);
        }

        logger.info("Loading changed files from {} to {}", startCommit.getShortHash(), endCommit.getShortHash());

        return git.listChangedFiles(repositoryName, startCommit.getHash(), endCommit.getHash())
            .thenApply(changedFiles -> {
                logger.debug("Got {} changed file lines from git", changedFiles.size());
                if (!changedFiles.isEmpty()) {
                    logger.debug("First few lines: {}", changedFiles.subList(0, Math.min(3, changedFiles.size())));
                }
                return parseChangedFiles(changedFiles, repositoryName);
            })
            .thenAccept(codeViewerModel::setAvailableFiles)
            .exceptionally(error -> {
                String errorMessage = error.getMessage();
                if (errorMessage != null && errorMessage.contains("bad object")) {
                    logger.error("Failed to load changed files - commit not found in local repository. " +
                                "Repository may need to be synced. Start: {}, End: {}",
                                startCommit.getShortHash(), endCommit.getShortHash(), error);
                } else {
                    logger.error("Failed to load changed files: {}", errorMessage, error);
                }
                codeViewerModel.setAvailableFiles(new ArrayList<>());
                return null;
            });
    }

    /**
     * Loads diff content for a specific file between two commits.
     * Loads both side-by-side content (left/right) and unified diff format.
     * Updates the model with file content.
     * Handles ADDED and DELETED files gracefully with appropriate placeholder messages.
     *
     * @param repositoryName name of the repository
     * @param file file to load diff for
     * @param startCommit starting commit for comparison
     * @param endCommit ending commit for comparison
     * @return future that completes when diff is loaded
     */
    public CompletableFuture<Void> loadDiffForFile(String repositoryName, ReviewFile file,
                                                     Commit startCommit, Commit endCommit) {
        if (file == null || startCommit == null || endCommit == null) {
            return CompletableFuture.completedFuture(null);
        }

        // For ADDED files, left side doesn't exist
        CompletableFuture<String> leftContentFuture;
        if (file.getChangeType() == FileChangeType.ADDED) {
            leftContentFuture = CompletableFuture.completedFuture(
                "// File does not exist in commit " + startCommit.getShortHash() + "\n" +
                "// This file was added in commit " + endCommit.getShortHash());
        } else {
            leftContentFuture = loadFileContent(repositoryName, file.getPath(), startCommit.getHash(), file);
        }

        // For DELETED files, right side doesn't exist
        CompletableFuture<String> rightContentFuture;
        if (file.getChangeType() == FileChangeType.DELETED) {
            rightContentFuture = CompletableFuture.completedFuture(
                "// File was deleted in commit " + endCommit.getShortHash() + "\n" +
                "// This file existed in commit " + startCommit.getShortHash());
        } else {
            rightContentFuture = loadFileContent(repositoryName, file.getPath(), endCommit.getHash(), file);
        }

        CompletableFuture<String> unifiedDiffFuture = loadUnifiedDiff(repositoryName,
            file.getPath(), startCommit.getHash(), endCommit.getHash());

        return CompletableFuture.allOf(leftContentFuture, rightContentFuture, unifiedDiffFuture)
            .thenAccept(ignored -> {
                String leftContent = leftContentFuture.join();
                String rightContent = rightContentFuture.join();
                String unifiedDiff = unifiedDiffFuture.join();

                codeViewerModel.setLeftContent(leftContent);
                codeViewerModel.setRightContent(rightContent);
                codeViewerModel.setUnifiedDiffContent(unifiedDiff);
            })
            .exceptionally(error -> {
                logger.error("Failed to load diff for file {}: {}", file.getPath(), error.getMessage());
                codeViewerModel.setLeftContent("// Error loading content: " + error.getMessage());
                codeViewerModel.setRightContent("// Error loading content: " + error.getMessage());
                codeViewerModel.setUnifiedDiffContent("// Error loading diff: " + error.getMessage());
                return null;
            });
    }

    /**
     * Loads diff content for a specific file between two branches.
     * This is used for multi-repository reviews where commit hashes don't match across repos.
     * Loads both side-by-side content (left/right) and unified diff format.
     * Updates the model with file content.
     *
     * @param repositoryName name of the repository
     * @param file file to load diff for
     * @param baseBranch base branch for comparison
     * @param reviewBranch review branch for comparison
     * @return future that completes when diff is loaded
     */
    public CompletableFuture<Void> loadDiffForFileWithBranches(String repositoryName, ReviewFile file,
                                                                 String baseBranch, String reviewBranch) {
        if (file == null || baseBranch == null || reviewBranch == null) {
            return CompletableFuture.completedFuture(null);
        }

        logger.info("Loading file diff using branches: repo={}, file={}, base={}, review={}",
            repositoryName, file.getPath(), baseBranch, reviewBranch);

        // For ADDED files, left side doesn't exist
        CompletableFuture<String> leftContentFuture;
        if (file.getChangeType() == FileChangeType.ADDED) {
            leftContentFuture = CompletableFuture.completedFuture(
                "// File does not exist in branch " + baseBranch + "\n" +
                "// This file was added in branch " + reviewBranch);
        } else {
            leftContentFuture = git.executeAsync(repositoryName, "show", baseBranch + ":" + file.getPath())
                .exceptionally(error -> {
                    logger.warn("Failed to load file {} from branch {}: {}", 
                        file.getPath(), baseBranch, error.getMessage());
                    return "// Error loading file from " + baseBranch + ": " + error.getMessage();
                });
        }

        // For DELETED files, right side doesn't exist
        CompletableFuture<String> rightContentFuture;
        if (file.getChangeType() == FileChangeType.DELETED) {
            rightContentFuture = CompletableFuture.completedFuture(
                "// File was deleted in branch " + reviewBranch + "\n" +
                "// This file existed in branch " + baseBranch);
        } else {
            rightContentFuture = git.executeAsync(repositoryName, "show", reviewBranch + ":" + file.getPath())
                .exceptionally(error -> {
                    logger.warn("Failed to load file {} from branch {}: {}", 
                        file.getPath(), reviewBranch, error.getMessage());
                    return "// Error loading file from " + reviewBranch + ": " + error.getMessage();
                });
        }

        CompletableFuture<String> unifiedDiffFuture = git.executeAsync(repositoryName,
            "diff", baseBranch, reviewBranch, "--", file.getPath())
            .exceptionally(error -> {
                logger.warn("Failed to generate unified diff for {}: {}", file.getPath(), error.getMessage());
                return "// Error generating diff: " + error.getMessage();
            });

        return CompletableFuture.allOf(leftContentFuture, rightContentFuture, unifiedDiffFuture)
            .thenAccept(ignored -> {
                String leftContent = leftContentFuture.join();
                String rightContent = rightContentFuture.join();
                String unifiedDiff = unifiedDiffFuture.join();

                codeViewerModel.setLeftContent(leftContent);
                codeViewerModel.setRightContent(rightContent);
                codeViewerModel.setUnifiedDiffContent(unifiedDiff);
            })
            .exceptionally(error -> {
                logger.error("Failed to load diff for file {}: {}", file.getPath(), error.getMessage());
                codeViewerModel.setLeftContent("// Error loading content: " + error.getMessage());
                codeViewerModel.setRightContent("// Error loading content: " + error.getMessage());
                codeViewerModel.setUnifiedDiffContent("// Error loading diff: " + error.getMessage());
                return null;
            });
    }

    /**
     * Refreshes the current view by reloading changed files and the currently selected file's diff.
     * Used when user clicks the refresh button.
     *
     * @param repositoryName name of the repository
     * @return future that completes when refresh is done
     */
    public CompletableFuture<Void> refreshCurrentView(String repositoryName) {
        Commit startCommit = codeViewerModel.startCommit.getValue();
        Commit endCommit = codeViewerModel.endCommit.getValue();
        ReviewFile currentFile = codeViewerModel.selectedFile.getValue();

        if (startCommit == null || endCommit == null) {
            return CompletableFuture.completedFuture(null);
        }

        CompletableFuture<Void> filesRefresh = loadChangedFiles(repositoryName, startCommit, endCommit);

        if (currentFile != null) {
            CompletableFuture<Void> diffRefresh = loadDiffForFile(repositoryName, currentFile,
                startCommit, endCommit);
            return CompletableFuture.allOf(filesRefresh, diffRefresh);
        }

        return filesRefresh;
    }

    private CompletableFuture<String> loadFileContent(String repositoryName, String filePath,
                                                       String commitHash, ReviewFile file) {
        return git.executeAsync(repositoryName, "show", commitHash + ":" + filePath)
            .exceptionally(error -> {
                String errorMsg = error.getMessage();

                // Handle cases where file doesn't exist in this commit
                if (errorMsg != null && (errorMsg.contains("does not exist") ||
                                        errorMsg.contains("not in") ||
                                        errorMsg.contains("path") && errorMsg.contains("exists on disk"))) {

                    if (file.getChangeType() == FileChangeType.ADDED) {
                        return "// File does not exist in this commit\n" +
                               "// File: " + filePath + "\n" +
                               "// This file was added in a later commit";
                    } else if (file.getChangeType() == FileChangeType.DELETED) {
                        return "// File was deleted in a later commit\n" +
                               "// File: " + filePath + "\n" +
                               "// This file existed in an earlier commit";
                    } else {
                        return "// File not available in commit " + commitHash.substring(0, 8) + "\n" +
                               "// File: " + filePath;
                    }
                }

                // Other errors
                logger.warn("Failed to load file content for {} at {}: {}",
                           filePath, commitHash, errorMsg);
                return "// Error loading file content\n" +
                       "// File: " + filePath + "\n" +
                       "// Error: " + errorMsg;
            });
    }

    private CompletableFuture<String> loadUnifiedDiff(String repositoryName, String filePath,
                                                        String fromCommit, String toCommit) {
        return git.executeAsync(repositoryName, "diff", fromCommit, toCommit, "--", filePath)
            .exceptionally(error -> {
                String errorMsg = error.getMessage();
                logger.warn("Failed to generate unified diff for {}: {}", filePath, errorMsg);

                // Return a descriptive message for the diff pane
                return "# Unable to generate diff\n" +
                       "# File: " + filePath + "\n" +
                       "# Error: " + errorMsg;
            });
    }

    private List<Commit> parseCommits(List<String> commitStrings) {
        List<Commit> commits = new ArrayList<>();
        for (String commitString : commitStrings) {
            try {
                String[] parts = commitString.split("\\|", 4);
                if (parts.length >= 4) {
                    commits.add(new Commit(parts[0], parts[3], parts[1], parts[2]));
                } else {
                    logger.warn("Skipping malformed commit line: '{}' (only {} parts)", commitString, parts.length);
                }
            } catch (Exception e) {
                logger.error("Error parsing commit line '{}': {}", commitString, e.getMessage(), e);
            }
        }
        return commits;
    }

    private List<ReviewFile> parseChangedFiles(List<String> changedFileStrings, String repositoryName) {
        List<ReviewFile> files = new ArrayList<>();
        for (String fileString : changedFileStrings) {
            try {
                String trimmed = fileString.trim();
                if (trimmed.isEmpty()) {
                    continue;
                }

                String[] parts = trimmed.split("\\s+", 2);
                if (parts.length >= 2) {
                    String status = parts[0];
                    String path = parts[1];
                    FileChangeType changeType = parseFileChangeType(status);
                    files.add(new ReviewFile(path, repositoryName, changeType));
                } else {
                    logger.warn("Skipping malformed changed file line: '{}' (only {} parts)", trimmed, parts.length);
                }
            } catch (Exception e) {
                logger.error("Error parsing changed file line '{}': {}", fileString, e.getMessage(), e);
            }
        }
        return files;
    }

    private FileChangeType parseFileChangeType(String status) {
        if (status == null || status.isEmpty()) {
            logger.warn("Empty or null status, defaulting to MODIFIED");
            return FileChangeType.MODIFIED;
        }
        return switch (status.toUpperCase().charAt(0)) {
            case 'A' -> FileChangeType.ADDED;
            case 'M' -> FileChangeType.MODIFIED;
            case 'D' -> FileChangeType.DELETED;
            case 'R' -> FileChangeType.RENAMED;
            default -> FileChangeType.MODIFIED;
        };
    }
}

package com.kalynx.serverlessreviewtool.managers;

import com.kalynx.serverlessreviewtool.git.Git;
import com.kalynx.serverlessreviewtool.git.GitReviewNotesManager;
import com.kalynx.serverlessreviewtool.models.FileChangeType;
import com.kalynx.serverlessreviewtool.models.ReviewContext;
import com.kalynx.serverlessreviewtool.models.ReviewFile;
import com.kalynx.serverlessreviewtool.models.ReviewStatus;
import com.kalynx.serverlessreviewtool.models.ReviewerInfo;
import com.kalynx.serverlessreviewtool.models.Repository;
import com.kalynx.serverlessreviewtool.models.review.StreamEntry;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.concurrent.CompletableFuture;
import java.util.function.Consumer;

/**
 * ReviewContextManager manages the lifecycle of a ReviewContext.
 * Responsibilities:
 * - Search across all repositories for review notes
 * - Load review metadata from git notes
 * - Create and maintain current ReviewContext
 * - Notify listeners when context changes
 *
 * Does NOT handle:
 * - Repository fetching (caller's responsibility)
 * - Commit loading (FileDiffManager's responsibility)
 * - File loading (FileDiffManager's responsibility)
 */
public class ReviewContextManager {

    private static final Logger LOGGER = LoggerFactory.getLogger(ReviewContextManager.class);

    private ReviewContext currentReviewContext;
    private final Git git;
    private final RepositoryManager repositoryManager;
    private final Set<Consumer<ReviewContext>> listeners = new HashSet<>();

    public ReviewContextManager(Git git, RepositoryManager repositoryManager) {
        this.git = git;
        this.repositoryManager = repositoryManager;
    }

    /**
     * Load review metadata by searching across all known repositories.
     * Uses an optimized batch read operation to minimize Git operations.
     * Does NOT handle repository syncing or file/commit loading.
     *
     * @param reviewId the review identifier
     * @return future that completes when ReviewContext is created and set
     */
    public CompletableFuture<ReviewContext> loadReviewMetadata(String reviewId) {
        if (reviewId == null || reviewId.isEmpty()) {
            return CompletableFuture.completedFuture(null);
        }

        LOGGER.info("Searching for review {} across all repositories", reviewId);

        List<Repository> allRepositories = repositoryManager.getRepositories();

        if (allRepositories.isEmpty()) {
            LOGGER.warn("No repositories configured, cannot load review {}", reviewId);
            return CompletableFuture.completedFuture(null);
        }

        return findReviewInRepositories(reviewId, allRepositories)
            .thenCompose(repositoryName -> {
                if (repositoryName == null) {
                    LOGGER.warn("Review {} not found in any repository", reviewId);
                    return CompletableFuture.completedFuture(null);
                }

                LOGGER.info("Found review {} in repository: {}", reviewId, repositoryName);
                return loadReviewFromRepositories(reviewId, repositoryName, allRepositories);
            });
    }

    /**
     * Load review metadata from specific repositories.
     * Uses the provided repository names to only search those repositories.
     * Does NOT handle repository syncing or file/commit loading.
     *
     * @param reviewId the review identifier
     * @param repositoryNames list of repository names to search
     * @return future that completes when ReviewContext is created and set
     */
    public CompletableFuture<ReviewContext> loadReviewMetadata(String reviewId, List<String> repositoryNames) {
        if (reviewId == null || reviewId.isEmpty()) {
            return CompletableFuture.completedFuture(null);
        }

        if (repositoryNames == null || repositoryNames.isEmpty()) {
            LOGGER.info("No specific repositories provided, searching all repositories for review {}", reviewId);
            return loadReviewMetadata(reviewId);
        }

        LOGGER.info("Loading review {} from specified {} repositories", reviewId, repositoryNames.size());

        List<Repository> specificRepositories = new ArrayList<>();
        for (String repoName : repositoryNames) {
            Repository repo = repositoryManager.getRepositoryByName(repoName);
            if (repo != null) {
                specificRepositories.add(repo);
            } else {
                LOGGER.warn("Repository '{}' not found in RepositoryManager", repoName);
            }
        }

        if (specificRepositories.isEmpty()) {
            LOGGER.warn("None of the specified repositories found, falling back to search all repositories");
            return loadReviewMetadata(reviewId);
        }

        return findReviewInRepositories(reviewId, specificRepositories)
            .thenCompose(repositoryName -> {
                if (repositoryName == null) {
                    LOGGER.warn("Review {} not found in specified repositories", reviewId);
                    return CompletableFuture.completedFuture(null);
                }

                LOGGER.info("Found review {} in repository: {}", reviewId, repositoryName);
                return loadReviewFromRepositories(reviewId, repositoryName, specificRepositories);
            });
    }

    private CompletableFuture<String> findReviewInRepositories(String reviewId, List<Repository> repositories) {
        List<CompletableFuture<String>> searchFutures = repositories.stream()
            .map(repo -> checkRepositoryForReview(reviewId, repo.getName()))
            .toList();

        return CompletableFuture.allOf(searchFutures.toArray(new CompletableFuture[0]))
            .thenApply(ignored -> {
                for (CompletableFuture<String> future : searchFutures) {
                    String repoName = future.join();
                    if (repoName != null) {
                        return repoName;
                    }
                }
                return null;
            });
    }

    private CompletableFuture<String> checkRepositoryForReview(String reviewId, String repositoryName) {
        GitReviewNotesManager notesManager = new GitReviewNotesManager(git, repositoryName);

        return notesManager.readTitles(reviewId)
            .thenApply(entries -> {
                if (entries != null && !entries.isEmpty()) {
                    LOGGER.debug("Review {} found in repository: {}", reviewId, repositoryName);
                    return repositoryName;
                }
                return null;
            })
            .exceptionally(error -> {
                LOGGER.debug("Review {} not found in repository {}: {}", reviewId, repositoryName, error.getMessage());
                return null;
            });
    }

    private CompletableFuture<ReviewContext> loadReviewFromRepositories(String reviewId, String repositoryName, List<Repository> allRepositories) {
        LOGGER.info("Loading review metadata: reviewId={}, repository={}", reviewId, repositoryName);

        GitReviewNotesManager notesManager = new GitReviewNotesManager(git, repositoryName);

        return notesManager.readAllMetadata(reviewId)
            .thenApply(metadata -> {
                String title = getLatestValue(metadata.titles());
                String description = getLatestValue(metadata.descriptions());
                String author = getLatestValue(metadata.authors());
                String statusStr = getLatestValue(metadata.statuses());

                List<String> reviewerNames = metadata.reviewers().stream()
                    .map(StreamEntry::editor)
                    .distinct()
                    .toList();

                if (title == null) title = "Untitled Review";
                if (description == null) description = "";
                if (author == null) author = "Unknown";
                if (statusStr == null) statusStr = "OPEN";

                LOGGER.info("Loaded review metadata: reviewId={}, title={}, author={}, reviewers={}",
                    reviewId, title, author, reviewerNames.size());

                ReviewStatus status = parseStatus(statusStr);
                List<ReviewerInfo> reviewers = reviewerNames.stream()
                    .map(ReviewerInfo::new)
                    .toList();

                List<Repository> reviewRepositories = new ArrayList<>();

                for (Repository repo : allRepositories) {
                    GitReviewNotesManager repoNotesManager = new GitReviewNotesManager(git, repo.getName());
                    try {
                        List<StreamEntry<String>> titles = repoNotesManager.readTitles(reviewId).get();
                        if (titles != null && !titles.isEmpty()) {
                            LOGGER.info("Review {} found in repository: {}", reviewId, repo.getName());
                            reviewRepositories.add(repo);
                        }
                    } catch (Exception e) {
                        LOGGER.debug("Review {} not found in repository {}", reviewId, repo.getName());
                    }
                }

                if (reviewRepositories.isEmpty()) {
                    Repository fallbackRepo = repositoryManager.getRepositoryByName(repositoryName);
                    if (fallbackRepo != null) {
                        reviewRepositories.add(fallbackRepo);
                    }
                    LOGGER.warn("Review {} not found in any repository, using fallback: {}", reviewId, repositoryName);
                }

                LOGGER.info("Review {} found in {} repositories", reviewId, reviewRepositories.size());

                ReviewContext reviewContext = new ReviewContext(
                    reviewId,
                    title,
                    description,
                    author,
                    status,
                    reviewers,
                    reviewRepositories,
                    new ArrayList<>()
                );

                setReviewContext(reviewContext);
                return reviewContext;
            }).exceptionally(error -> {
                LOGGER.error("Failed to load review metadata for {}: {}", reviewId, error.getMessage(), error);
                return null;
            });
    }

    /**
     * Load files changed in a review by comparing branch against base branch.
     * Returns a list of ReviewFile objects representing all changed files in the review.
     *
     * @param repositoryName the repository containing the review
     * @param reviewBranch the branch being reviewed (e.g., "feature/my-feature" or "origin/feature/my-feature")
     * @param baseBranch the base branch to compare against (e.g., "main" or "origin/main")
     * @return future that completes with list of ReviewFile objects
     */
    public CompletableFuture<List<ReviewFile>> loadFilesForReview(
            String repositoryName,
            String reviewBranch,
            String baseBranch) {

        if (repositoryName == null || reviewBranch == null || baseBranch == null) {
            LOGGER.warn("Invalid parameters for loading files: repo={}, reviewBranch={}, baseBranch={}",
                repositoryName, reviewBranch, baseBranch);
            return CompletableFuture.completedFuture(new ArrayList<>());
        }

        LOGGER.info("Loading files for review in repository '{}': {} -> {}",
            repositoryName, baseBranch, reviewBranch);

        return git.listChangedFiles(repositoryName, baseBranch, reviewBranch)
            .thenApply(changedFilePaths -> {
                LOGGER.info("Git diff returned {} changed file paths for repository '{}'",
                    changedFilePaths.size(), repositoryName);

                List<ReviewFile> reviewFiles = changedFilePaths.stream()
                    .map(filePath -> new ReviewFile(filePath, repositoryName, FileChangeType.MODIFIED))
                    .toList();

                LOGGER.info("Loaded {} files for review in repository '{}'",
                    reviewFiles.size(), repositoryName);

                return reviewFiles;
            })
            .exceptionally(error -> {
                LOGGER.error("Failed to load files for review in repository '{}': {}",
                    repositoryName, error.getMessage(), error);
                return new ArrayList<>();
            });
    }

    public CompletableFuture<List<ReviewFile>> loadFilesForAllRepositories(
            List<Repository> repositories,
            String reviewBranch,
            String baseBranch) {

        if (repositories == null || repositories.isEmpty()) {
            LOGGER.warn("No repositories provided for loading files");
            return CompletableFuture.completedFuture(new ArrayList<>());
        }

        LOGGER.info("Loading files from {} repositories", repositories.size());

        List<CompletableFuture<List<ReviewFile>>> fileFutures = repositories.stream()
            .map(repo -> loadFilesForReview(repo.getName(), reviewBranch, baseBranch))
            .toList();

        return CompletableFuture.allOf(fileFutures.toArray(new CompletableFuture[0]))
            .thenApply(ignored -> {
                List<ReviewFile> allFiles = new ArrayList<>();
                for (CompletableFuture<List<ReviewFile>> future : fileFutures) {
                    allFiles.addAll(future.join());
                }

                LOGGER.info("Loaded total of {} files across all repositories", allFiles.size());
                return allFiles;
            })
            .exceptionally(error -> {
                LOGGER.error("Failed to load files from all repositories: {}", error.getMessage(), error);
                return new ArrayList<>();
            });
    }

    public CompletableFuture<List<ReviewFile>> loadFilesFromReviewCommits(String reviewId, List<Repository> repositories) {
        if (repositories == null || repositories.isEmpty()) {
            LOGGER.warn("No repositories provided for loading files");
            return CompletableFuture.completedFuture(new ArrayList<>());
        }

        LOGGER.info("Loading files from review branches for {} repositories", repositories.size());

        Repository primaryRepo = repositories.getFirst();
        GitReviewNotesManager notesManager = new GitReviewNotesManager(git, primaryRepo.getName());

        return notesManager.readAllMetadata(reviewId)
            .thenCompose(metadata -> {
                String branch = getLatestValue(metadata.branches());
                String baseBranch = getLatestValue(metadata.baseBranches());

                LOGGER.info("=== FILE LOADING DEBUG ===");
                LOGGER.info("Review ID: {}", reviewId);
                LOGGER.info("Branch: {}", branch);
                LOGGER.info("BaseBranch: {}", baseBranch);
                LOGGER.info("Number of repositories: {}", repositories.size());

                if (branch == null || baseBranch == null) {
                    LOGGER.warn("Missing branch or baseBranch metadata for review {}", reviewId);
                    return CompletableFuture.completedFuture(new ArrayList<ReviewFile>());
                }

                LOGGER.info("Loading files from branch '{}' compared to '{}'", branch, baseBranch);

                List<CompletableFuture<List<ReviewFile>>> fileFutures = repositories.stream()
                    .map(repo -> {
                        LOGGER.info("Loading files from repository: {}", repo.getName());
                        return loadFilesForReview(repo.getName(), branch, baseBranch);
                    })
                    .toList();

                return CompletableFuture.allOf(fileFutures.toArray(new CompletableFuture[0]))
                    .thenApply(ignored -> {
                        List<ReviewFile> allFiles = new ArrayList<>();
                        for (int i = 0; i < fileFutures.size(); i++) {
                            List<ReviewFile> repoFiles = fileFutures.get(i).join();
                            LOGGER.info("Repository '{}' returned {} files", repositories.get(i).getName(), repoFiles.size());
                            for (ReviewFile file : repoFiles) {
                                LOGGER.info("  - {}", file.getPath());
                            }
                            allFiles.addAll(repoFiles);
                        }

                        LOGGER.info("=== TOTAL: {} files loaded from review branches across all repositories ===", allFiles.size());
                        return allFiles;
                    });
            })
            .exceptionally(error -> {
                LOGGER.error("Failed to load files from review branches: {}", error.getMessage(), error);
                return new ArrayList<ReviewFile>();
            });
    }

    private CompletableFuture<List<ReviewFile>> loadFilesForReviewFromCommits(String reviewId, String repositoryName) {
        LOGGER.info("Loading files from review commits for repository '{}'", repositoryName);

        GitReviewNotesManager notesManager = new GitReviewNotesManager(git, repositoryName);

        return notesManager.readCommits(reviewId)
            .thenCompose(commitEntries -> {
                if (commitEntries == null || commitEntries.isEmpty()) {
                    LOGGER.warn("No commits found for review {} in repository {}", reviewId, repositoryName);
                    return CompletableFuture.completedFuture(new ArrayList<>());
                }

                List<String> commits = commitEntries.get(commitEntries.size() - 1).data();

                if (commits == null || commits.isEmpty()) {
                    LOGGER.warn("Empty commits list for review {} in repository {}", reviewId, repositoryName);
                    return CompletableFuture.completedFuture(new ArrayList<>());
                }

                LOGGER.info("Found {} commits for review {} in repository {}", commits.size(), reviewId, repositoryName);

                String firstCommit = commits.get(commits.size() - 1);
                String lastCommit = commits.get(0);

                String compareBase = firstCommit + "^";

                return git.listChangedFiles(repositoryName, compareBase, lastCommit)
                    .thenApply(changedFilePaths -> {
                        List<ReviewFile> reviewFiles = changedFilePaths.stream()
                            .map(filePath -> new ReviewFile(filePath, repositoryName, FileChangeType.MODIFIED))
                            .toList();

                        LOGGER.info("Loaded {} files from commits in repository '{}'",
                            reviewFiles.size(), repositoryName);

                        return reviewFiles;
                    })
                    .exceptionally(error -> {
                        LOGGER.error("Failed to load files from commits in repository '{}': {}",
                            repositoryName, error.getMessage(), error);
                        return new ArrayList<>();
                    });
            });
    }

    /**
     * Set the current ReviewContext and notify all listeners.
     */
    public void setReviewContext(ReviewContext reviewContext) {
        this.currentReviewContext = reviewContext;
        LOGGER.info("ReviewContext set: {}", reviewContext != null ? reviewContext.getReviewId() : "null");
        notifyListeners();
    }

    /**
     * Get the current ReviewContext.
     */
    public ReviewContext getReviewContext() {
        return currentReviewContext;
    }

    /**
     * Clear the current ReviewContext.
     */
    public void clearReviewContext() {
        this.currentReviewContext = null;
        LOGGER.info("ReviewContext cleared");
        notifyListeners();
    }

    /**
     * Add a listener for ReviewContext changes.
     * Listener is immediately called with current context.
     */
    public void addListener(Consumer<ReviewContext> listener) {
        listeners.add(listener);
        listener.accept(currentReviewContext);
    }

    /**
     * Remove a listener.
     */
    public void removeListener(Consumer<ReviewContext> listener) {
        listeners.remove(listener);
    }

    private void notifyListeners() {
        LOGGER.debug("Notifying {} listeners of ReviewContext change", listeners.size());
        listeners.forEach(listener -> listener.accept(currentReviewContext));
    }

    private <T> T getLatestValue(List<StreamEntry<T>> entries) {
        if (entries == null || entries.isEmpty()) {
            return null;
        }
        return entries.get(entries.size() - 1).data();
    }

    private ReviewStatus parseStatus(String statusStr) {
        if (statusStr == null) {
            return ReviewStatus.OPEN;
        }
        try {
            return ReviewStatus.valueOf(statusStr.toUpperCase());
        } catch (IllegalArgumentException e) {
            LOGGER.warn("Unknown review status: {}, defaulting to OPEN", statusStr);
            return ReviewStatus.OPEN;
        }
    }
}

package com.kalynx.serverlessreviewtool.managers;

import com.kalynx.serverlessreviewtool.git.Git;
import com.kalynx.serverlessreviewtool.git.GitReviewNotesManager;
import com.kalynx.serverlessreviewtool.models.FileChangeType;
import com.kalynx.serverlessreviewtool.models.ReviewContext;
import com.kalynx.serverlessreviewtool.models.ReviewFile;
import com.kalynx.serverlessreviewtool.models.ReviewStatus;
import com.kalynx.serverlessreviewtool.models.ReviewerInfo;
import com.kalynx.serverlessreviewtool.models.Repository;
import com.kalynx.serverlessreviewtool.models.review.StreamEntry;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.concurrent.CompletableFuture;
import java.util.function.Consumer;

/**
 * ReviewContextManager manages the lifecycle of a ReviewContext.
 * Responsibilities:
 * - Search across all repositories for review notes
 * - Load review metadata from git notes
 * - Create and maintain current ReviewContext
 * - Notify listeners when context changes
 *
 * Does NOT handle:
 * - Repository fetching (caller's responsibility)
 * - Commit loading (FileDiffManager's responsibility)
 * - File loading (FileDiffManager's responsibility)
 */
public class ReviewContextManager {

    private static final Logger LOGGER = LoggerFactory.getLogger(ReviewContextManager.class);

    private ReviewContext currentReviewContext;
    private final Git git;
    private final RepositoryManager repositoryManager;
    private final Set<Consumer<ReviewContext>> listeners = new HashSet<>();

    public ReviewContextManager(Git git, RepositoryManager repositoryManager) {
        this.git = git;
        this.repositoryManager = repositoryManager;
    }

    /**
     * Load review metadata by searching across all known repositories.
     * Uses an optimized batch read operation to minimize Git operations.
     * Does NOT handle repository syncing or file/commit loading.
     *
     * @param reviewId the review identifier
     * @return future that completes when ReviewContext is created and set
     */
    public CompletableFuture<ReviewContext> loadReviewMetadata(String reviewId) {
        if (reviewId == null || reviewId.isEmpty()) {
            return CompletableFuture.completedFuture(null);
        }

        LOGGER.info("Searching for review {} across all repositories", reviewId);

        List<Repository> allRepositories = repositoryManager.getRepositories();

        if (allRepositories.isEmpty()) {
            LOGGER.warn("No repositories configured, cannot load review {}", reviewId);
            return CompletableFuture.completedFuture(null);
        }

        return findReviewInRepositories(reviewId, allRepositories)
            .thenCompose(repositoryName -> {
                if (repositoryName == null) {
                    LOGGER.warn("Review {} not found in any repository", reviewId);
                    return CompletableFuture.completedFuture(null);
                }

                LOGGER.info("Found review {} in repository: {}", reviewId, repositoryName);
                return loadReviewFromRepositories(reviewId, repositoryName, allRepositories);
            });
    }

    /**
     * Load review metadata from specific repositories.
     * Uses the provided repository names to only search those repositories.
     * Does NOT handle repository syncing or file/commit loading.
     *
     * @param reviewId the review identifier
     * @param repositoryNames list of repository names to search
     * @return future that completes when ReviewContext is created and set
     */
    public CompletableFuture<ReviewContext> loadReviewMetadata(String reviewId, List<String> repositoryNames) {
        if (reviewId == null || reviewId.isEmpty()) {
            return CompletableFuture.completedFuture(null);
        }

        if (repositoryNames == null || repositoryNames.isEmpty()) {
            LOGGER.info("No specific repositories provided, searching all repositories for review {}", reviewId);
            return loadReviewMetadata(reviewId);
        }

        LOGGER.info("Loading review {} from specified {} repositories", reviewId, repositoryNames.size());

        List<Repository> specificRepositories = new ArrayList<>();
        for (String repoName : repositoryNames) {
            Repository repo = repositoryManager.getRepositoryByName(repoName);
            if (repo != null) {
                specificRepositories.add(repo);
            } else {
                LOGGER.warn("Repository '{}' not found in RepositoryManager", repoName);
            }
        }

        if (specificRepositories.isEmpty()) {
            LOGGER.warn("None of the specified repositories found, falling back to search all repositories");
            return loadReviewMetadata(reviewId);
        }

        return findReviewInRepositories(reviewId, specificRepositories)
            .thenCompose(repositoryName -> {
                if (repositoryName == null) {
                    LOGGER.warn("Review {} not found in specified repositories", reviewId);
                    return CompletableFuture.completedFuture(null);
                }

                LOGGER.info("Found review {} in repository: {}", reviewId, repositoryName);
                return loadReviewFromRepositories(reviewId, repositoryName, specificRepositories);
            });
    }

    private CompletableFuture<String> findReviewInRepositories(String reviewId, List<Repository> repositories) {
        List<CompletableFuture<String>> searchFutures = repositories.stream()
            .map(repo -> checkRepositoryForReview(reviewId, repo.getName()))
            .toList();

        return CompletableFuture.allOf(searchFutures.toArray(new CompletableFuture[0]))
            .thenApply(ignored -> {
                for (CompletableFuture<String> future : searchFutures) {
                    String repoName = future.join();
                    if (repoName != null) {
                        return repoName;
                    }
                }
                return null;
            });
    }

    private CompletableFuture<String> checkRepositoryForReview(String reviewId, String repositoryName) {
        GitReviewNotesManager notesManager = new GitReviewNotesManager(git, repositoryName);

        return notesManager.readTitles(reviewId)
            .thenApply(entries -> {
                if (entries != null && !entries.isEmpty()) {
                    LOGGER.debug("Review {} found in repository: {}", reviewId, repositoryName);
                    return repositoryName;
                }
                return null;
            })
            .exceptionally(error -> {
                LOGGER.debug("Review {} not found in repository {}: {}", reviewId, repositoryName, error.getMessage());
                return null;
            });
    }

    private CompletableFuture<ReviewContext> loadReviewFromRepositories(String reviewId, String repositoryName, List<Repository> allRepositories) {
        LOGGER.info("Loading review metadata: reviewId={}, repository={}", reviewId, repositoryName);

        GitReviewNotesManager notesManager = new GitReviewNotesManager(git, repositoryName);

        return notesManager.readAllMetadata(reviewId)
            .thenApply(metadata -> {
                String title = getLatestValue(metadata.titles());
                String description = getLatestValue(metadata.descriptions());
                String author = getLatestValue(metadata.authors());
                String statusStr = getLatestValue(metadata.statuses());

                List<String> reviewerNames = metadata.reviewers().stream()
                    .map(StreamEntry::editor)
                    .distinct()
                    .toList();

                if (title == null) title = "Untitled Review";
                if (description == null) description = "";
                if (author == null) author = "Unknown";
                if (statusStr == null) statusStr = "OPEN";

                LOGGER.info("Loaded review metadata: reviewId={}, title={}, author={}, reviewers={}",
                    reviewId, title, author, reviewerNames.size());

                ReviewStatus status = parseStatus(statusStr);
                List<ReviewerInfo> reviewers = reviewerNames.stream()
                    .map(ReviewerInfo::new)
                    .toList();

                List<Repository> reviewRepositories = new ArrayList<>();

                for (Repository repo : allRepositories) {
                    GitReviewNotesManager repoNotesManager = new GitReviewNotesManager(git, repo.getName());
                    try {
                        List<StreamEntry<String>> titles = repoNotesManager.readTitles(reviewId).get();
                        if (titles != null && !titles.isEmpty()) {
                            LOGGER.info("Review {} found in repository: {}", reviewId, repo.getName());
                            reviewRepositories.add(repo);
                        }
                    } catch (Exception e) {
                        LOGGER.debug("Review {} not found in repository {}", reviewId, repo.getName());
                    }
                }

                if (reviewRepositories.isEmpty()) {
                    Repository fallbackRepo = repositoryManager.getRepositoryByName(repositoryName);
                    if (fallbackRepo != null) {
                        reviewRepositories.add(fallbackRepo);
                    }
                    LOGGER.warn("Review {} not found in any repository, using fallback: {}", reviewId, repositoryName);
                }

                LOGGER.info("Review {} found in {} repositories", reviewId, reviewRepositories.size());

                ReviewContext reviewContext = new ReviewContext(
                    reviewId,
                    title,
                    description,
                    author,
                    status,
                    reviewers,
                    reviewRepositories,
                    new ArrayList<>()
                );

                setReviewContext(reviewContext);
                return reviewContext;
            }).exceptionally(error -> {
                LOGGER.error("Failed to load review metadata for {}: {}", reviewId, error.getMessage(), error);
                return null;
            });
    }

    /**
     * Load files changed in a review by comparing branch against base branch.
     * Returns a list of ReviewFile objects representing all changed files in the review.
     *
     * @param repositoryName the repository containing the review
     * @param reviewBranch the branch being reviewed (e.g., "feature/my-feature" or "origin/feature/my-feature")
     * @param baseBranch the base branch to compare against (e.g., "main" or "origin/main")
     * @return future that completes with list of ReviewFile objects
     */
    public CompletableFuture<List<ReviewFile>> loadFilesForReview(
            String repositoryName,
            String reviewBranch,
            String baseBranch) {

        if (repositoryName == null || reviewBranch == null || baseBranch == null) {
            LOGGER.warn("Invalid parameters for loading files: repo={}, reviewBranch={}, baseBranch={}",
                repositoryName, reviewBranch, baseBranch);
            return CompletableFuture.completedFuture(new ArrayList<>());
        }

        LOGGER.info("Loading files for review in repository '{}': {} -> {}",
            repositoryName, baseBranch, reviewBranch);

        return git.listChangedFiles(repositoryName, baseBranch, reviewBranch)
            .thenApply(changedFilePaths -> {
                LOGGER.info("Git diff returned {} changed file paths for repository '{}'",
                    changedFilePaths.size(), repositoryName);

                List<ReviewFile> reviewFiles = changedFilePaths.stream()
                    .map(filePath -> parseChangedFileLine(filePath, repositoryName, baseBranch, reviewBranch))
                    .toList();

                LOGGER.info("Loaded {} files for review in repository '{}'",
                    reviewFiles.size(), repositoryName);

                return reviewFiles;
            })
            .exceptionally(error -> {
                LOGGER.error("Failed to load files for review in repository '{}': {}",
                    repositoryName, error.getMessage(), error);
                return new ArrayList<>();
            });
    }

    private ReviewFile parseChangedFileLine(String line, String repositoryName, 
                                            String baseBranch, String reviewBranch) {
        String trimmed = line.trim();
        String[] parts = trimmed.split("\\s+", 2);

        if (parts.length >= 2) {
            String status = parts[0];
            String path = parts[1];
            FileChangeType changeType = parseFileChangeType(status);
            return new ReviewFile(path, repositoryName, changeType, baseBranch, reviewBranch);
        } else {
            LOGGER.warn("Malformed file line: '{}', defaulting to MODIFIED", line);
            return new ReviewFile(trimmed, repositoryName, FileChangeType.MODIFIED, baseBranch, reviewBranch);
        }
    }

    private FileChangeType parseFileChangeType(String status) {
        if (status == null || status.isEmpty()) {
            return FileChangeType.MODIFIED;
        }
        return switch (status.toUpperCase().charAt(0)) {
            case 'A' -> FileChangeType.ADDED;
            case 'M' -> FileChangeType.MODIFIED;
            case 'D' -> FileChangeType.DELETED;
            case 'R' -> FileChangeType.RENAMED;
            default -> FileChangeType.MODIFIED;
        };
    }

    public CompletableFuture<List<ReviewFile>> loadFilesForAllRepositories(
            List<Repository> repositories,
            String reviewBranch,
            String baseBranch) {

        if (repositories == null || repositories.isEmpty()) {
            LOGGER.warn("No repositories provided for loading files");
            return CompletableFuture.completedFuture(new ArrayList<>());
        }

        LOGGER.info("Loading files from {} repositories", repositories.size());

        List<CompletableFuture<List<ReviewFile>>> fileFutures = repositories.stream()
            .map(repo -> loadFilesForReview(repo.getName(), reviewBranch, baseBranch))
            .toList();

        return CompletableFuture.allOf(fileFutures.toArray(new CompletableFuture[0]))
            .thenApply(ignored -> {
                List<ReviewFile> allFiles = new ArrayList<>();
                for (CompletableFuture<List<ReviewFile>> future : fileFutures) {
                    allFiles.addAll(future.join());
                }

                LOGGER.info("Loaded total of {} files across all repositories", allFiles.size());
                return allFiles;
            })
            .exceptionally(error -> {
                LOGGER.error("Failed to load files from all repositories: {}", error.getMessage(), error);
                return new ArrayList<>();
            });
    }

    public CompletableFuture<List<ReviewFile>> loadFilesFromReviewCommits(String reviewId, List<Repository> repositories) {
        if (repositories == null || repositories.isEmpty()) {
            LOGGER.warn("No repositories provided for loading files");
            return CompletableFuture.completedFuture(new ArrayList<>());
        }

        LOGGER.info("Loading files from review branches for {} repositories", repositories.size());

        Repository primaryRepo = repositories.getFirst();
        GitReviewNotesManager notesManager = new GitReviewNotesManager(git, primaryRepo.getName());

        return notesManager.readAllMetadata(reviewId)
            .thenCompose(metadata -> {
                String branch = getLatestValue(metadata.branches());
                String baseBranch = getLatestValue(metadata.baseBranches());

                LOGGER.info("=== FILE LOADING DEBUG ===");
                LOGGER.info("Review ID: {}", reviewId);
                LOGGER.info("Branch: {}", branch);
                LOGGER.info("BaseBranch: {}", baseBranch);
                LOGGER.info("Number of repositories: {}", repositories.size());

                if (branch == null || baseBranch == null) {
                    LOGGER.warn("Missing branch or baseBranch metadata for review {}", reviewId);
                    return CompletableFuture.completedFuture(new ArrayList<ReviewFile>());
                }

                LOGGER.info("Loading files from branch '{}' compared to '{}'", branch, baseBranch);

                List<CompletableFuture<List<ReviewFile>>> fileFutures = repositories.stream()
                    .map(repo -> {
                        LOGGER.info("Loading files from repository: {}", repo.getName());
                        return loadFilesForReview(repo.getName(), branch, baseBranch);
                    })
                    .toList();

                return CompletableFuture.allOf(fileFutures.toArray(new CompletableFuture[0]))
                    .thenApply(ignored -> {
                        List<ReviewFile> allFiles = new ArrayList<>();
                        for (int i = 0; i < fileFutures.size(); i++) {
                            List<ReviewFile> repoFiles = fileFutures.get(i).join();
                            LOGGER.info("Repository '{}' returned {} files", repositories.get(i).getName(), repoFiles.size());
                            for (ReviewFile file : repoFiles) {
                                LOGGER.info("  - {}", file.getPath());
                            }
                            allFiles.addAll(repoFiles);
                        }

                        LOGGER.info("=== TOTAL: {} files loaded from review branches across all repositories ===", allFiles.size());
                        return allFiles;
                    });
            })
            .exceptionally(error -> {
                LOGGER.error("Failed to load files from review branches: {}", error.getMessage(), error);
                return new ArrayList<ReviewFile>();
            });
    }

    private CompletableFuture<List<ReviewFile>> loadFilesForReviewFromCommits(String reviewId, String repositoryName) {
        LOGGER.info("Loading files from review commits for repository '{}'", repositoryName);

        GitReviewNotesManager notesManager = new GitReviewNotesManager(git, repositoryName);

        return notesManager.readCommits(reviewId)
            .thenCompose(commitEntries -> {
                if (commitEntries == null || commitEntries.isEmpty()) {
                    LOGGER.warn("No commits found for review {} in repository {}", reviewId, repositoryName);
                    return CompletableFuture.completedFuture(new ArrayList<>());
                }

                List<String> commits = commitEntries.get(commitEntries.size() - 1).data();

                if (commits == null || commits.isEmpty()) {
                    LOGGER.warn("Empty commits list for review {} in repository {}", reviewId, repositoryName);
                    return CompletableFuture.completedFuture(new ArrayList<>());
                }

                LOGGER.info("Found {} commits for review {} in repository {}", commits.size(), reviewId, repositoryName);

                String firstCommit = commits.get(commits.size() - 1);
                String lastCommit = commits.get(0);

                String compareBase = firstCommit + "^";

                return git.listChangedFiles(repositoryName, compareBase, lastCommit)
                    .thenApply(changedFilePaths -> {
                        List<ReviewFile> reviewFiles = changedFilePaths.stream()
                            .map(filePath -> new ReviewFile(filePath, repositoryName, FileChangeType.MODIFIED))
                            .toList();

                        LOGGER.info("Loaded {} files from commits in repository '{}'",
                            reviewFiles.size(), repositoryName);

                        return reviewFiles;
                    })
                    .exceptionally(error -> {
                        LOGGER.error("Failed to load files from commits in repository '{}': {}",
                            repositoryName, error.getMessage(), error);
                        return new ArrayList<>();
                    });
            });
    }

    /**
     * Set the current ReviewContext and notify all listeners.
     */
    public void setReviewContext(ReviewContext reviewContext) {
        this.currentReviewContext = reviewContext;
        LOGGER.info("ReviewContext set: {}", reviewContext != null ? reviewContext.getReviewId() : "null");
        notifyListeners();
    }

    /**
     * Get the current ReviewContext.
     */
    public ReviewContext getReviewContext() {
        return currentReviewContext;
    }

    /**
     * Clear the current ReviewContext.
     */
    public void clearReviewContext() {
        this.currentReviewContext = null;
        LOGGER.info("ReviewContext cleared");
        notifyListeners();
    }

    /**
     * Add a listener for ReviewContext changes.
     * Listener is immediately called with current context.
     */
    public void addListener(Consumer<ReviewContext> listener) {
        listeners.add(listener);
        listener.accept(currentReviewContext);
    }

    /**
     * Remove a listener.
     */
    public void removeListener(Consumer<ReviewContext> listener) {
        listeners.remove(listener);
    }

    private void notifyListeners() {
        LOGGER.debug("Notifying {} listeners of ReviewContext change", listeners.size());
        listeners.forEach(listener -> listener.accept(currentReviewContext));
    }

    private <T> T getLatestValue(List<StreamEntry<T>> entries) {
        if (entries == null || entries.isEmpty()) {
            return null;
        }
        return entries.get(entries.size() - 1).data();
    }

    private ReviewStatus parseStatus(String statusStr) {
        if (statusStr == null) {
            return ReviewStatus.OPEN;
        }
        try {
            return ReviewStatus.valueOf(statusStr.toUpperCase());
        } catch (IllegalArgumentException e) {
            LOGGER.warn("Unknown review status: {}, defaulting to OPEN", statusStr);
            return ReviewStatus.OPEN;
        }
    }
}

package com.kalynx.serverlessreviewtool.models;

/**
 * ReviewFile - Represents a file in the review
 */
public class ReviewFile {
    private final String path;
    private final String repository;
    private final FileChangeType changeType;

    public ReviewFile(String path, String repository, FileChangeType changeType) {
        this.path = path;
        this.repository = repository;
        this.changeType = changeType;
    }

    public String getPath() {
        return path;
    }

    public String getRepository() {
        return repository;
    }

    public FileChangeType getChangeType() {
        return changeType;
    }

    public String getFileName() {
        int lastSlash = path.lastIndexOf('/');
        return lastSlash >= 0 ? path.substring(lastSlash + 1) : path;
    }

    public String getDirectory() {
        int lastSlash = path.lastIndexOf('/');
        return lastSlash >= 0 ? path.substring(0, lastSlash) : "";
    }

    @Override
    public String toString() {
        return path;
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (!(obj instanceof ReviewFile)) return false;
        ReviewFile other = (ReviewFile) obj;
        return path.equals(other.path) && repository.equals(other.repository);
    }

    @Override
    public int hashCode() {
        return path.hashCode() + repository.hashCode();
    }
}

