    public void toggleDiffMode() {
        diffMode.setValue(diffMode.getValue() == DiffMode.SIDE_BY_SIDE
            ? DiffMode.UNIFIED
            : DiffMode.SIDE_BY_SIDE);
    }

    public void setDiffMode(DiffMode mode) {
