import java.util.List;

/**
 * CommitSelectorPanel - Custom dual-slider for commit range selection for specific files
 * Displays commits that touched the currently selected file and allows selection of commit range
 */
public class CommitSelectorPanel extends ThemedPanel {
    @Serial
    private static final long serialVersionUID = 1L;
    private static final Logger LOGGER = LoggerFactory.getLogger(CommitSelectorPanel.class);

    private transient final ReviewContextManager reviewContextManager;
    private transient final CodeViewerModel codeViewerModel;
    private transient final Git git;

    private ThemedComboBox<DiffViewMode> viewModeComboBox;
    private CommitSliderPanel commitSliderPanel;

    private transient final List<CommitRangeListener> commitRangeListeners = new ArrayList<>();
    private transient final List<ViewModeListener> viewModeListeners = new ArrayList<>();

    public CommitSelectorPanel(ReviewContextManager reviewContextManager, CodeViewerModel codeViewerModel, Git git) {
        this.reviewContextManager = reviewContextManager;
        this.codeViewerModel = codeViewerModel;
        this.git = git;
        configureLayout();
        setupListeners();
        setupModelListeners();
    }

    private void configureLayout() {
        setLayout(new MigLayout("fillx, insets 0", "[grow]10[][]", "[]"));

        commitSliderPanel = new CommitSliderPanel();
        add(commitSliderPanel, "growx, h 50!");

        ThemedLabel viewLabel = new ThemedLabel("View:");
        viewModeComboBox = new ThemedComboBox<>(DiffViewMode.values());
        viewModeComboBox.setSelectedItem(DiffViewMode.SIDE_BY_SIDE);
        viewModeComboBox.addActionListener(ignored -> onViewModeChanged());

        add(viewLabel);
        add(viewModeComboBox, "w 120!");
    }

    private void setupListeners() {
        reviewContextManager.addListener(this::onReviewContextChanged);
    }

    private void setupModelListeners() {
        codeViewerModel.selectedFile.addChangeListener(this::onFileSelected);
    }

    private void onFileSelected(ReviewFile file) {
        if (file != null) {
            loadCommitsForFile(file);
        } else {
            commitSliderPanel.setCommits(new ArrayList<>());
        }
    }

    private void loadCommitsForFile(ReviewFile file) {
        String repositoryName = file.getRepository();
        String filePath = file.getPath();

        String branch = codeViewerModel.reviewBranch.getValue();
        if (branch == null) {
            LOGGER.warn("No review branch set, cannot load file commits");
            return;
        }

        LOGGER.info("Loading commits for file: {} in repository: {}", filePath, repositoryName);

        git.executeAsync(repositoryName, "log", "--format=%H|%an|%ad|%s", "--date=short", "--follow", branch, "--", filePath)
            .thenAccept(output -> {
                List<Commit> commits = parseCommits(output.lines().toList());
                LOGGER.info("Loaded {} commits for file {}", commits.size(), filePath);

                List<Commit> reversedCommits = new ArrayList<>(commits);
                java.util.Collections.reverse(reversedCommits);

                commitSliderPanel.setCommits(reversedCommits);

                if (!reversedCommits.isEmpty()) {
                    commitSliderPanel.setStartIndex(0);
                    commitSliderPanel.setEndIndex(reversedCommits.size() - 1);
                    fireCommitRangeChanged(reversedCommits.getFirst(), reversedCommits.getLast());
                }
            })
            .exceptionally(error -> {
                LOGGER.error("Failed to load commits for file {}: {}", filePath, error.getMessage());
                commitSliderPanel.setCommits(new ArrayList<>());
                return null;
            });
    }

    private List<Commit> parseCommits(List<String> commitStrings) {
        List<Commit> commits = new ArrayList<>();
        for (String commitString : commitStrings) {
            try {
                String[] parts = commitString.split("\\|", 4);
                if (parts.length >= 4) {
                    commits.add(new Commit(parts[0], parts[3], parts[1], parts[2]));
                }
            } catch (Exception e) {
                LOGGER.error("Error parsing commit line: {}", commitString, e);
            }
        }
        return commits;
    }

    private void onReviewContextChanged(ReviewContext context) {
    }

    private void onViewModeChanged() {
        DiffViewMode mode = (DiffViewMode) viewModeComboBox.getSelectedItem();
        if (mode != null) {
            fireViewModeChanged(mode);
        }
    }

    public Commit getStartCommit() {
        return commitSliderPanel.getStartCommit();
    }

    public Commit getEndCommit() {
        return commitSliderPanel.getEndCommit();
    }

    public interface CommitRangeListener {
        void onCommitRangeChanged(Commit startCommit, Commit endCommit);
    }

    public interface ViewModeListener {
        void onViewModeChanged(DiffViewMode mode);
    }

    public void addCommitRangeListener(CommitRangeListener listener) {
        commitRangeListeners.add(listener);
    }

    public void addViewModeListener(ViewModeListener listener) {
        viewModeListeners.add(listener);
    }

    private void fireCommitRangeChanged(Commit startCommit, Commit endCommit) {
        codeViewerModel.setCommitRange(startCommit, endCommit);
        for (CommitRangeListener listener : commitRangeListeners) {
            listener.onCommitRangeChanged(startCommit, endCommit);
        }
    }

    private void fireViewModeChanged(DiffViewMode mode) {
        for (ViewModeListener listener : viewModeListeners) {
            listener.onViewModeChanged(mode);
        }
    }



    /**
     * Custom slider panel with two thumbs for selecting commit range
     */
    private class CommitSliderPanel extends ThemedPanel {
        @Serial
        private static final long serialVersionUID = 1L;

        private transient List<Commit> commits = new ArrayList<>();
        private int startIndex = 0;
        private int endIndex = 0;
        private int dragThumb = -1;
        private final int THUMB_RADIUS = themeManager.scale(6);
        private final int TRACK_HEIGHT = themeManager.scale(3);
        private final int MARGIN = themeManager.scale(20);

        private ThemedWindow tooltipWindow;
        private ThemedLabel tooltipLabel;

        public CommitSliderPanel() {
            setupMouseListeners();
            createTooltipWindow();
        }

        private void createTooltipWindow() {
            tooltipWindow = new ThemedWindow();

            tooltipLabel = new ThemedLabel();
            tooltipLabel.setFont(new Font("Segoe UI", Font.PLAIN, themeManager.scale(11)));

            tooltipWindow.setContent(tooltipLabel);
        }

        private void setupMouseListeners() {
            MouseAdapter mouseAdapter = new MouseAdapter() {
                @Override
                public void mousePressed(MouseEvent e) {
                    if (commits.isEmpty()) return;

                    int startThumbX = getThumbX(startIndex);
                    int endThumbX = getThumbX(endIndex);
                    int thumbY = getHeight() / 2 + themeManager.scale(5);

                    if (isNearPoint(e.getX(), e.getY(), startThumbX, thumbY, THUMB_RADIUS)) {
                        dragThumb = 0;
                        showTooltipForIndex(startIndex);
                    } else if (isNearPoint(e.getX(), e.getY(), endThumbX, thumbY, THUMB_RADIUS)) {
                        dragThumb = 1;
                        showTooltipForIndex(endIndex);
                    } else {
                        int index = getIndexFromX(e.getX());
                        showTooltipForIndex(index);
                    }
                }

                @Override
                public void mouseReleased(MouseEvent e) {
                    if (dragThumb != -1 && !commits.isEmpty()) {
                        fireCommitRangeChanged(commits.get(startIndex), commits.get(endIndex));
                    }
                    dragThumb = -1;
                    hideTooltip();
                }

                @Override
                public void mouseDragged(MouseEvent e) {
                    if (dragThumb == -1 || commits.isEmpty()) return;

                    int newIndex = getIndexFromX(e.getX());

                    if (dragThumb == 0) {
                        startIndex = Math.max(0, Math.min(newIndex, endIndex - 1));
                        showTooltipForIndex(startIndex);
                    } else {
                        endIndex = Math.max(startIndex + 1, Math.min(newIndex, commits.size() - 1));
                        showTooltipForIndex(endIndex);
                    }

                    repaint();
                }
            };

            addMouseListener(mouseAdapter);
            addMouseMotionListener(mouseAdapter);
        }

        private void showTooltipForIndex(int index) {
            if (commits.isEmpty()) return;

            index = Math.max(0, Math.min(index, commits.size() - 1));
            Commit commit = commits.get(index);

            String tooltipText = String.format(
                "<html><b>%s</b><br/>%s<br/><i>%s - %s</i></html>",
                commit.getHash().substring(0, Math.min(7, commit.getHash().length())),
                commit.getMessage(),
                commit.getAuthor(),
                commit.getDate()
            );
            tooltipLabel.setText(tooltipText);

            tooltipWindow.pack();

            Point locationOnScreen = getLocationOnScreen();
            int thumbX = getThumbX(index);
            int thumbY = getHeight() / 2 + themeManager.scale(5);

            int tooltipX = locationOnScreen.x + thumbX - tooltipWindow.getWidth() / 2;
            int tooltipY = locationOnScreen.y + thumbY - tooltipWindow.getHeight() - themeManager.scale(10);

            tooltipWindow.showAt(tooltipX, tooltipY);
        }

        private void hideTooltip() {
            if (tooltipWindow != null) {
                tooltipWindow.setVisible(false);
            }
        }


        private boolean isNearPoint(int x, int y, int centerX, int centerY, int radius) {
            int dx = x - centerX;
            int dy = y - centerY;
            return Math.sqrt(dx * dx + dy * dy) <= radius + 5;
        }

        private int getThumbX(int index) {
            if (commits.size() <= 1) return MARGIN;
            int trackWidth = getWidth() - 2 * MARGIN;
            return MARGIN + (index * trackWidth) / (commits.size() - 1);
        }

        private int getIndexFromX(int x) {
            if (commits.size() <= 1) return 0;
            int trackWidth = getWidth() - 2 * MARGIN;
            int index = Math.round((float) (x - MARGIN) * (commits.size() - 1) / trackWidth);
            return Math.max(0, Math.min(index, commits.size() - 1));
        }

        public void setCommits(List<Commit> commits) {
            this.commits = new ArrayList<>(commits);
            this.startIndex = 0;
            this.endIndex = Math.max(0, commits.size() - 1);
            repaint();
        }

        public void setStartIndex(int index) {
            this.startIndex = Math.max(0, Math.min(index, commits.size() - 1));
            repaint();
        }

        public void setEndIndex(int index) {
            this.endIndex = Math.max(0, Math.min(index, commits.size() - 1));
            repaint();
        }

        public Commit getStartCommit() {
            if (commits.isEmpty() || startIndex >= commits.size()) return null;
            return commits.get(startIndex);
        }

        public Commit getEndCommit() {
            if (commits.isEmpty() || endIndex >= commits.size()) return null;
            return commits.get(endIndex);
        }

        @Override
        protected void paintComponent(Graphics g) {
            super.paintComponent(g);
            if (commits.isEmpty()) return;

            Graphics2D g2 = (Graphics2D) g.create();
            g2.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);

            Theme theme = themeManager.getCurrentTheme();
            int width = getWidth();
            int height = getHeight();
            int centerY = height / 2 + themeManager.scale(5);
            int trackWidth = width - 2 * MARGIN;

            g2.setFont(new Font("Consolas", Font.PLAIN, themeManager.scale(9)));
            FontMetrics fm = g2.getFontMetrics();

            int[] visibleIndices = getVisibleCommitIndices();
            for (int i : visibleIndices) {
                if (i >= 0 && i < commits.size()) {
                    int x = getThumbX(i);
                    String hash = commits.get(i).getHash().substring(0, Math.min(6, commits.get(i).getHash().length()));
                    int textWidth = fm.stringWidth(hash);

                    g2.setColor(theme.getSecondaryTextColor());
                    g2.drawString(hash, x - textWidth / 2, centerY - themeManager.scale(12));

                    g2.setColor(theme.getBorderColor());
                    g2.fillOval(x - 2, centerY - TRACK_HEIGHT / 2 - 2, 4, 4);
                }
            }

            g2.setColor(theme.getBorderColor());
            g2.fillRoundRect(MARGIN, centerY - TRACK_HEIGHT / 2, trackWidth, TRACK_HEIGHT, TRACK_HEIGHT, TRACK_HEIGHT);

            int startX = getThumbX(startIndex);
            int endX = getThumbX(endIndex);
            g2.setColor(theme.getAccentColor());
            g2.fillRoundRect(startX, centerY - TRACK_HEIGHT / 2, endX - startX, TRACK_HEIGHT, TRACK_HEIGHT, TRACK_HEIGHT);

            drawThumb(g2, startX, centerY, startIndex == dragThumb, theme);
            drawThumb(g2, endX, centerY, endIndex == dragThumb, theme);

            g2.dispose();
        }

        private int[] getVisibleCommitIndices() {
            if (commits.size() <= 3) {
                int[] indices = new int[commits.size()];
                for (int i = 0; i < commits.size(); i++) {
                    indices[i] = i;
                }
                return indices;
            } else if (commits.size() <= 10) {
                return new int[]{0, commits.size() / 2, commits.size() - 1};
            } else {
                return new int[]{0, commits.size() - 1};
            }
        }

        private void drawThumb(Graphics2D g2, int x, int y, boolean isDragging, Theme theme) {
            int radius = isDragging ? THUMB_RADIUS + 2 : THUMB_RADIUS;

            g2.setColor(theme.getBackgroundColor());
            g2.fillOval(x - radius, y - radius, radius * 2, radius * 2);

            g2.setColor(theme.getAccentColor());
            g2.setStroke(new BasicStroke(themeManager.scale(2)));
            g2.drawOval(x - radius, y - radius, radius * 2, radius * 2);

            if (isDragging) {
                g2.setColor(new Color(theme.getAccentColor().getRed(),
                                      theme.getAccentColor().getGreen(),
                                      theme.getAccentColor().getBlue(), 80));
                g2.fillOval(x - radius - 3, y - radius - 3, (radius + 3) * 2, (radius + 3) * 2);
            }
        }
    }
}

package com.kalynx.serverlessreviewtool.ui.review;

import java.io.Serial;

import com.kalynx.serverlessreviewtool.models.*;
import com.kalynx.serverlessreviewtool.swingextensions.themedcomponents.LineNumberedTextPane;
import com.kalynx.serverlessreviewtool.swingextensions.themedcomponents.ThemedPanel;
import com.kalynx.serverlessreviewtool.swingextensions.themedcomponents.ThemedScrollPane;
import com.kalynx.serverlessreviewtool.swingextensions.themedcomponents.ThemedSplitPane;
import com.kalynx.serverlessreviewtool.theme.ThemeManager;
import com.kalynx.serverlessreviewtool.theme.Theme;
import com.kalynx.serverlessreviewtool.ui.models.mainpanels.reviewpanel.CodeViewerModel;

import javax.swing.*;
import javax.swing.text.*;
import java.awt.*;

/**
 * DiffViewerPanel - Shows file diffs in side-by-side or unified mode
 */
public class DiffViewerPanel extends ThemedPanel {
    @Serial
    private static final long serialVersionUID = 1L;

    private transient final ThemeManager themeManager = ThemeManager.getInstance();
    private transient final CodeViewerModel codeViewerModel;

    private DiffViewMode currentMode = DiffViewMode.SIDE_BY_SIDE;
    private ThemedPanel contentPanel;

    private LineNumberedTextPane leftPane;
    private LineNumberedTextPane rightPane;
    private LineNumberedTextPane unifiedPane;

    private transient ReviewFile currentFile;
    private transient Commit startCommit;
    private transient Commit endCommit;
    private transient Theme lastRenderedTheme;

    public DiffViewerPanel(CodeViewerModel codeViewerModel) {
        this.codeViewerModel = codeViewerModel;
        setLayout(new BorderLayout());
        initializeComponents();
    }

    private void initializeComponents() {

        contentPanel = new ThemedPanel(new CardLayout());

        // Create side-by-side view
        createSideBySideView();

        // Create unified view
        createUnifiedView();

        add(contentPanel, BorderLayout.CENTER);

        // Show initial view
        switchViewMode();
    }

    private void createSideBySideView() {
        // Create line numbered panes for both sides
        leftPane = new LineNumberedTextPane();
        rightPane = new LineNumberedTextPane();

        // Wrap in scroll panes
        ThemedScrollPane leftScrollPane = new ThemedScrollPane(leftPane);
        leftScrollPane.setVerticalScrollBarPolicy(JScrollPane.VERTICAL_SCROLLBAR_ALWAYS);
        leftScrollPane.setHorizontalScrollBarPolicy(JScrollPane.HORIZONTAL_SCROLLBAR_AS_NEEDED);

        ThemedScrollPane rightScrollPane = new ThemedScrollPane(rightPane);
        rightScrollPane.setVerticalScrollBarPolicy(JScrollPane.VERTICAL_SCROLLBAR_ALWAYS);
        rightScrollPane.setHorizontalScrollBarPolicy(JScrollPane.HORIZONTAL_SCROLLBAR_AS_NEEDED);

        // Synchronize scrolling between left and right panes
        synchronizeScrollPanes(leftScrollPane, rightScrollPane);

        // Create split pane with the two scrolled line-numbered panes
        ThemedSplitPane splitPane = new ThemedSplitPane(JSplitPane.HORIZONTAL_SPLIT, leftScrollPane, rightScrollPane);
        splitPane.setResizeWeight(0.5);

        contentPanel.add(splitPane, DiffViewMode.SIDE_BY_SIDE.name());
    }

    private void createUnifiedView() {
        unifiedPane = new LineNumberedTextPane();

        // Wrap in scroll pane
        ThemedScrollPane unifiedScrollPane = new ThemedScrollPane(unifiedPane);
        unifiedScrollPane.setVerticalScrollBarPolicy(JScrollPane.VERTICAL_SCROLLBAR_ALWAYS);
        unifiedScrollPane.setHorizontalScrollBarPolicy(JScrollPane.HORIZONTAL_SCROLLBAR_AS_NEEDED);

        contentPanel.add(unifiedScrollPane, DiffViewMode.UNIFIED.name());
    }

    private void synchronizeScrollPanes(ThemedScrollPane leftPane, ThemedScrollPane rightPane) {
        // Link vertical scroll bars
        JScrollBar leftScrollBar = leftPane.getVerticalScrollBar();
        JScrollBar rightScrollBar = rightPane.getVerticalScrollBar();

        if (leftScrollBar != null && rightScrollBar != null) {
            leftScrollBar.addAdjustmentListener(e -> {
                if (!e.getValueIsAdjusting()) {
                    rightScrollBar.setValue(e.getValue());
                }
            });

            rightScrollBar.addAdjustmentListener(e -> {
                if (!e.getValueIsAdjusting()) {
                    leftScrollBar.setValue(e.getValue());
                }
            });
        }
    }

    private void switchViewMode() {
        CardLayout layout = (CardLayout) contentPanel.getLayout();
        layout.show(contentPanel, currentMode.name());

        if (currentFile != null) {
            showDiff(currentFile, startCommit, endCommit);
        }
    }

    public void setViewMode(DiffViewMode mode) {
        if (mode != null && mode != currentMode) {
            currentMode = mode;
            switchViewMode();
        }
    }

    public void showDiff(ReviewFile file, Commit newStartCommit, Commit newEndCommit) {
        this.currentFile = file;
        this.startCommit = newStartCommit;
        this.endCommit = newEndCommit;
        this.lastRenderedTheme = themeManager.getCurrentTheme();

        if (currentMode == DiffViewMode.SIDE_BY_SIDE) {
            showSideBySideDiff(file, newStartCommit, newEndCommit);
        } else {
            showUnifiedDiff(file, newStartCommit, newEndCommit);
        }
    }

    private void showSideBySideDiff(ReviewFile file, Commit startCommit, Commit endCommit) {
        // Get content from model
        String beforeContent = codeViewerModel.leftContent.getValue();
        String afterContent = codeViewerModel.rightContent.getValue();

        // Fall back to emptyif not available
        if (beforeContent == null || beforeContent.isEmpty()) {
            beforeContent = "// Content not available for " + file.getPath();
        }
        if (afterContent == null || afterContent.isEmpty()) {
            afterContent = "// Content not available for " + file.getPath();
        }

        // Set content and apply highlighting
        highlightDiffWithInlineChanges(leftPane, rightPane, beforeContent, afterContent);
    }

    private void showUnifiedDiff(ReviewFile file, Commit startCommit, Commit endCommit) {
        // Get unified diff from model
        String unifiedDiff = codeViewerModel.unifiedDiffContent.getValue();

        // Fall back to placeholder if not available
        if (unifiedDiff == null || unifiedDiff.isEmpty()) {
            unifiedDiff = "// Unified diff not available for " + file.getPath();
        }

        highlightUnifiedDiff(unifiedPane, unifiedDiff);
    }

    private String generateSampleContent(ReviewFile file, Commit commit, boolean isOld) {
        // This is a placeholder - in a real app, you'd fetch actual file content from Git
        StringBuilder sb = new StringBuilder();
        sb.append("// ").append(file.getPath()).append("\n");
        sb.append("// Commit: ").append(commit.getShortHash()).append("\n");
        sb.append("\n");

        if (file.getChangeType() == FileChangeType.ADDED && isOld) {
            sb.append("// File does not exist in this commit\n");
        } else if (file.getChangeType() == FileChangeType.DELETED && !isOld) {
            sb.append("// File was deleted\n");
        } else {
            // Initial section - unchanged
            sb.append("public class Example {\n");
            sb.append("    private String name;\n");
            sb.append("    private int age;\n");
            sb.append("    \n");
            sb.append("    public Example(String name) {\n");
            sb.append("        this.name = name;\n");
            sb.append("    }\n");
            sb.append("    \n");

            // MIDDLE SECTION - Different for old vs new version
            if (isOld) {
                // OLD VERSION - Content that will be removed
                sb.append("    // Configuration section (WILL BE REMOVED)\n");
                sb.append("    private static final String CONFIG_PATH = \"/etc/config\";\n");
                sb.append("    private static final int MAX_RETRIES = 3;\n");
                sb.append("    private static final long TIMEOUT_MS = 5000;\n");
                sb.append("    \n");
                sb.append("    public void updateConfig() {  // DELETED METHOD\n");
                sb.append("        System.out.println(\"Updating config\");\n");
                sb.append("    }\n");
                sb.append("    \n");
            } else {
                // NEW VERSION - New content added
                sb.append("    // Logging section (NEW)\n");
                sb.append("    private static final Logger logger = LoggerFactory.getLogger(Example.class);\n");
                sb.append("    private static final String LOG_LEVEL = \"INFO\";\n");
                sb.append("    \n");
                sb.append("    // Authentication section (NEW)\n");
                sb.append("    private AuthProvider authProvider;  // NEW FIELD\n");
                sb.append("    private boolean isAuthenticated = false;  // NEW FIELD\n");
                sb.append("    \n");
            }

            // Final section - unchanged
            sb.append("    public String getName() {\n");
            sb.append("        return name;\n");
            sb.append("    }\n");
            sb.append("    \n");
            sb.append("    public int getAge() {\n");
            sb.append("        return age;\n");
            sb.append("    }\n");
            sb.append("    \n");

            if (isOld) {
                sb.append("    public void processRequest() {  // WILL BE MODIFIED\n");
                sb.append("        // Old implementation\n");
                sb.append("        String data = readData();\n");
                sb.append("    }\n");
            } else {
                sb.append("    public void processRequest() {  // MODIFIED METHOD\n");
                sb.append("        // New implementation with authentication\n");
                sb.append("        if (!isAuthenticated) return;  // NEW\n");
                sb.append("        String data = readData();\n");
                sb.append("        logger.info(\"Processing request\");  // NEW\n");
                sb.append("    }\n");
            }

            sb.append("}\n");
        }

        return sb.toString();
    }

    @SuppressWarnings({"unused", "UnusedParameters"})
    private String generateUnifiedDiff(ReviewFile file, Commit _startCommit, Commit _endCommit) {
        return "--- a/" + file.getPath() + "\n" +
                "+++ b/" + file.getPath() + "\n" +
                "@@ -1,25 +1,30 @@\n" +
                " public class Example {\n" +
                "     private String name;\n" +
                "     private int age;\n" +
                "     \n" +
                "     public Example(String name) {\n" +
                "         this.name = name;\n" +
                "     }\n" +
                "     \n" +
                "-    // Configuration section (WILL BE REMOVED)\n" +
                "-    private static final String CONFIG_PATH = \"/etc/config\";\n" +
                "-    private static final int MAX_RETRIES = 3;\n" +
                "-    private static final long TIMEOUT_MS = 5000;\n" +
                "-    \n" +
                "-    public void updateConfig() {  // DELETED METHOD\n" +
                "-        System.out.println(\"Updating config\");\n" +
                "-    }\n" +
                "-    \n" +
                "+    // Logging section (NEW)\n" +
                "+    private static final Logger logger = LoggerFactory.getLogger(Example.class);\n" +
                "+    private static final String LOG_LEVEL = \"INFO\";\n" +
                "+    \n" +
                "+    // Authentication section (NEW)\n" +
                "+    private AuthProvider authProvider;  // NEW FIELD\n" +
                "+    private boolean isAuthenticated = false;  // NEW FIELD\n" +
                "+    \n" +
                "     public String getName() {\n" +
                "         return name;\n" +
                "     }\n" +
                "     \n" +
                "     public int getAge() {\n" +
                "         return age;\n" +
                "     }\n" +
                "     \n" +
                "-    public void processRequest() {  // WILL BE MODIFIED\n" +
                "-        // Old implementation\n" +
                "-        String data = readData();\n" +
                "+    public void processRequest() {  // MODIFIED METHOD\n" +
                "+        // New implementation with authentication\n" +
                "+        if (!isAuthenticated) return;  // NEW\n" +
                "+        String data = readData();\n" +
                "+        logger.info(\"Processing request\");  // NEW\n" +
                "     }\n" +
                " }\n";
    }

    private void highlightDiffWithInlineChanges(LineNumberedTextPane leftPane, LineNumberedTextPane rightPane,
                                                 String beforeContent, String afterContent) {
        // Set text in both panes
        leftPane.setText(beforeContent);
        rightPane.setText(afterContent);

        Theme theme = themeManager.getCurrentTheme();
        JTextPane leftTextPane = leftPane.getTextPane();
        JTextPane rightTextPane = rightPane.getTextPane();

        StyledDocument leftDoc = leftTextPane.getStyledDocument();
        StyledDocument rightDoc = rightTextPane.getStyledDocument();

        // Create styles - set both foreground (theme) and background (highlight)
        // because setCharacterAttributes with replace=true wipes all attributes
        Style removedStyle = leftTextPane.addStyle("removed", null);
        StyleConstants.setForeground(removedStyle, theme.getForegroundColor());
        StyleConstants.setBackground(removedStyle, theme.getRemovedLineColor());

        Style addedStyle = rightTextPane.addStyle("added", null);
        StyleConstants.setForeground(addedStyle, theme.getForegroundColor());
        StyleConstants.setBackground(addedStyle, theme.getAddedLineColor());

        Style defaultStyle = leftTextPane.addStyle("default", null);
        StyleConstants.setForeground(defaultStyle, theme.getForegroundColor());

        Style defaultStyleRight = rightTextPane.addStyle("default", null);
        StyleConstants.setForeground(defaultStyleRight, theme.getForegroundColor());

        // Split into lines and compare
        String[] beforeLines = beforeContent.split("\n", -1);
        String[] afterLines = afterContent.split("\n", -1);

        int beforeOffset = 0;
        int afterOffset = 0;

        int maxLines = Math.max(beforeLines.length, afterLines.length);
        for (int i = 0; i < maxLines; i++) {
            String beforeLine = i < beforeLines.length ? beforeLines[i] : "";
            String afterLine = i < afterLines.length ? afterLines[i] : "";

            int beforeLineLength = beforeLine.length() + 1;
            int afterLineLength = afterLine.length() + 1;

            // Apply default style first
            if (beforeOffset + beforeLineLength <= leftDoc.getLength()) {
                leftDoc.setCharacterAttributes(beforeOffset, beforeLineLength, defaultStyle, true);
            }
            if (afterOffset + afterLineLength <= rightDoc.getLength()) {
                rightDoc.setCharacterAttributes(afterOffset, afterLineLength, defaultStyleRight, true);
            }

            // Find and highlight differences within the line
            if (!beforeLine.equals(afterLine)) {
                // Find common prefix
                int commonPrefix = 0;
                int minLen = Math.min(beforeLine.length(), afterLine.length());
                while (commonPrefix < minLen && beforeLine.charAt(commonPrefix) == afterLine.charAt(commonPrefix)) {
                    commonPrefix++;
                }

                // Find common suffix
                int commonSuffix = 0;
                while (commonSuffix < minLen - commonPrefix &&
                       beforeLine.charAt(beforeLine.length() - 1 - commonSuffix) ==
                       afterLine.charAt(afterLine.length() - 1 - commonSuffix)) {
                    commonSuffix++;
                }

                // Highlight the differences
                if (commonPrefix < beforeLine.length() - commonSuffix) {
                    int diffLength = beforeLine.length() - commonPrefix - commonSuffix;
                    leftDoc.setCharacterAttributes(beforeOffset + commonPrefix, diffLength, removedStyle, true);
                }

                if (commonPrefix < afterLine.length() - commonSuffix) {
                    int diffLength = afterLine.length() - commonPrefix - commonSuffix;
                    rightDoc.setCharacterAttributes(afterOffset + commonPrefix, diffLength, addedStyle, true);
                }
            }

            beforeOffset += beforeLineLength;
            afterOffset += afterLineLength;
        }
    }

    private void highlightUnifiedDiff(LineNumberedTextPane pane, String unifiedDiff) {
        pane.setText(unifiedDiff);

        Theme theme = themeManager.getCurrentTheme();
        JTextPane textPane = pane.getTextPane();
        StyledDocument doc = textPane.getStyledDocument();

        // Create styles - set both foreground (theme) and background (highlight)
        // because setCharacterAttributes with replace=true wipes all attributes
        Style addedStyle = textPane.addStyle("added", null);
        StyleConstants.setForeground(addedStyle, theme.getForegroundColor());
        StyleConstants.setBackground(addedStyle, theme.getAddedLineColor());

        Style removedStyle = textPane.addStyle("removed", null);
        StyleConstants.setForeground(removedStyle, theme.getForegroundColor());
        StyleConstants.setBackground(removedStyle, theme.getRemovedLineColor());

        Style defaultStyle = textPane.addStyle("default", null);
        StyleConstants.setForeground(defaultStyle, theme.getForegroundColor());

        // Apply styles based on line prefixes
        String[] lines = unifiedDiff.split("\n");
        int offset = 0;
        int lineNumber = 1;
        for (String line : lines) {
            int lineLength = line.length() + 1; // +1 for newline

            if (line.startsWith("+") && !line.startsWith("+++")) {
                doc.setCharacterAttributes(offset, lineLength, addedStyle, true);
                pane.markLineAdded(lineNumber);
            } else if (line.startsWith("-") && !line.startsWith("---")) {
                doc.setCharacterAttributes(offset, lineLength, removedStyle, true);
                pane.markLineRemoved(lineNumber);
            } else {
                doc.setCharacterAttributes(offset, lineLength, defaultStyle, true);
            }

            offset += lineLength;
            lineNumber++;
        }
    }

    public void clear() {
        leftPane.setText("");
        rightPane.setText("");
        unifiedPane.setText("");
        currentFile = null;
    }


    public void setOnLineDoubleClickListener(java.util.function.Consumer<Integer> listener) {
        leftPane.setOnLineDoubleClickListener(listener);
        rightPane.setOnLineDoubleClickListener(listener);
        unifiedPane.setOnLineDoubleClickListener(listener);
    }

    public void setCommentsForCurrentFile(java.util.List<ReviewComment> comments) {
        leftPane.setComments(comments);
        rightPane.setComments(comments);
        unifiedPane.setComments(comments);
    }

    @Override
    public void paint(Graphics g) {
        if (currentFile != null && lastRenderedTheme != themeManager.getCurrentTheme()) {
            showDiff(currentFile, startCommit, endCommit);
        }
        super.paint(g);
    }
}

package com.kalynx.serverlessreviewtool.ui.review;

import java.io.Serial;

import com.kalynx.serverlessreviewtool.models.*;
import com.kalynx.serverlessreviewtool.swingextensions.themedcomponents.LineNumberedTextPane;
import com.kalynx.serverlessreviewtool.swingextensions.themedcomponents.ThemedPanel;
import com.kalynx.serverlessreviewtool.swingextensions.themedcomponents.ThemedScrollPane;
import com.kalynx.serverlessreviewtool.swingextensions.themedcomponents.ThemedSplitPane;
import com.kalynx.serverlessreviewtool.theme.ThemeManager;
import com.kalynx.serverlessreviewtool.theme.Theme;
import com.kalynx.serverlessreviewtool.ui.models.mainpanels.reviewpanel.CodeViewerModel;

import javax.swing.*;
import javax.swing.text.*;
import java.awt.*;

/**
 * DiffViewerPanel - Shows file diffs in side-by-side or unified mode
 */
public class DiffViewerPanel extends ThemedPanel {
    @Serial
    private static final long serialVersionUID = 1L;

    private transient final ThemeManager themeManager = ThemeManager.getInstance();
    private transient final CodeViewerModel codeViewerModel;

    private DiffViewMode currentMode = DiffViewMode.SIDE_BY_SIDE;
    private ThemedPanel contentPanel;

    private LineNumberedTextPane leftPane;
    private LineNumberedTextPane rightPane;
    private LineNumberedTextPane unifiedPane;

    private transient ReviewFile currentFile;
    private transient Commit startCommit;
    private transient Commit endCommit;
    private transient Theme lastRenderedTheme;

    public DiffViewerPanel(CodeViewerModel codeViewerModel) {
        this.codeViewerModel = codeViewerModel;
        setLayout(new BorderLayout());
        initializeComponents();
        setupModelListeners();
    }

    private void initializeComponents() {

        contentPanel = new ThemedPanel(new CardLayout());

        // Create side-by-side view
        createSideBySideView();

        // Create unified view
        createUnifiedView();

        add(contentPanel, BorderLayout.CENTER);

        // Show initial view
        switchViewMode();
    }

    private void setupModelListeners() {
        codeViewerModel.leftContent.addChangeListener(content -> updateLeftContent());
        codeViewerModel.rightContent.addChangeListener(content -> updateRightContent());
        codeViewerModel.unifiedDiffContent.addChangeListener(content -> updateUnifiedContent());
        codeViewerModel.diffMode.addChangeListener(mode -> {
            if (mode == CodeViewerModel.DiffMode.SIDE_BY_SIDE) {
                setViewMode(DiffViewMode.SIDE_BY_SIDE);
            } else {
                setViewMode(DiffViewMode.UNIFIED);
            }
        });
        codeViewerModel.selectedFile.addChangeListener(file -> {
            this.currentFile = file;
            this.startCommit = codeViewerModel.startCommit.getValue();
            this.endCommit = codeViewerModel.endCommit.getValue();
        });
    }

    private void updateLeftContent() {
        String content = codeViewerModel.leftContent.getValue();
        if (content != null && leftPane != null) {
            SwingUtilities.invokeLater(() -> leftPane.setText(content));
        }
    }

    private void updateRightContent() {
        String content = codeViewerModel.rightContent.getValue();
        if (content != null && rightPane != null) {
            SwingUtilities.invokeLater(() -> rightPane.setText(content));
        }
    }

    private void updateUnifiedContent() {
        String content = codeViewerModel.unifiedDiffContent.getValue();
        if (content != null && unifiedPane != null) {
            SwingUtilities.invokeLater(() -> unifiedPane.setText(content));
        }
    }

    private void createSideBySideView() {
        // Create line numbered panes for both sides
        leftPane = new LineNumberedTextPane();
        rightPane = new LineNumberedTextPane();

        // Wrap in scroll panes
        ThemedScrollPane leftScrollPane = new ThemedScrollPane(leftPane);
        leftScrollPane.setVerticalScrollBarPolicy(JScrollPane.VERTICAL_SCROLLBAR_ALWAYS);
        leftScrollPane.setHorizontalScrollBarPolicy(JScrollPane.HORIZONTAL_SCROLLBAR_AS_NEEDED);

        ThemedScrollPane rightScrollPane = new ThemedScrollPane(rightPane);
        rightScrollPane.setVerticalScrollBarPolicy(JScrollPane.VERTICAL_SCROLLBAR_ALWAYS);
        rightScrollPane.setHorizontalScrollBarPolicy(JScrollPane.HORIZONTAL_SCROLLBAR_AS_NEEDED);

        // Synchronize scrolling between left and right panes
        synchronizeScrollPanes(leftScrollPane, rightScrollPane);

        // Create split pane with the two scrolled line-numbered panes
        ThemedSplitPane splitPane = new ThemedSplitPane(JSplitPane.HORIZONTAL_SPLIT, leftScrollPane, rightScrollPane);
        splitPane.setResizeWeight(0.5);

        contentPanel.add(splitPane, DiffViewMode.SIDE_BY_SIDE.name());
    }

    private void createUnifiedView() {
        unifiedPane = new LineNumberedTextPane();

        // Wrap in scroll pane
        ThemedScrollPane unifiedScrollPane = new ThemedScrollPane(unifiedPane);
        unifiedScrollPane.setVerticalScrollBarPolicy(JScrollPane.VERTICAL_SCROLLBAR_ALWAYS);
        unifiedScrollPane.setHorizontalScrollBarPolicy(JScrollPane.HORIZONTAL_SCROLLBAR_AS_NEEDED);

        contentPanel.add(unifiedScrollPane, DiffViewMode.UNIFIED.name());
    }

    private void synchronizeScrollPanes(ThemedScrollPane leftPane, ThemedScrollPane rightPane) {
        // Link vertical scroll bars
        JScrollBar leftScrollBar = leftPane.getVerticalScrollBar();
        JScrollBar rightScrollBar = rightPane.getVerticalScrollBar();

        if (leftScrollBar != null && rightScrollBar != null) {
            leftScrollBar.addAdjustmentListener(e -> {
                if (!e.getValueIsAdjusting()) {
                    rightScrollBar.setValue(e.getValue());
                }
            });

            rightScrollBar.addAdjustmentListener(e -> {
                if (!e.getValueIsAdjusting()) {
                    leftScrollBar.setValue(e.getValue());
                }
            });
        }
    }

    private void switchViewMode() {
        CardLayout layout = (CardLayout) contentPanel.getLayout();
        layout.show(contentPanel, currentMode.name());

        if (currentFile != null) {
            showDiff(currentFile, startCommit, endCommit);
        }
    }

    public void setViewMode(DiffViewMode mode) {
        if (mode != null && mode != currentMode) {
            currentMode = mode;
            switchViewMode();
        }
    }

    public void showDiff(ReviewFile file, Commit newStartCommit, Commit newEndCommit) {
        this.currentFile = file;
        this.startCommit = newStartCommit;
        this.endCommit = newEndCommit;
        this.lastRenderedTheme = themeManager.getCurrentTheme();

        if (currentMode == DiffViewMode.SIDE_BY_SIDE) {
            showSideBySideDiff(file, newStartCommit, newEndCommit);
        } else {
            showUnifiedDiff(file, newStartCommit, newEndCommit);
        }
    }

    private void showSideBySideDiff(ReviewFile file, Commit startCommit, Commit endCommit) {
        // Get content from model
        String beforeContent = codeViewerModel.leftContent.getValue();
        String afterContent = codeViewerModel.rightContent.getValue();

        // Fall back to emptyif not available
        if (beforeContent == null || beforeContent.isEmpty()) {
            beforeContent = "// Content not available for " + file.getPath();
        }
        if (afterContent == null || afterContent.isEmpty()) {
            afterContent = "// Content not available for " + file.getPath();
        }

        // Set content and apply highlighting
        highlightDiffWithInlineChanges(leftPane, rightPane, beforeContent, afterContent);
    }

    private void showUnifiedDiff(ReviewFile file, Commit startCommit, Commit endCommit) {
        // Get unified diff from model
        String unifiedDiff = codeViewerModel.unifiedDiffContent.getValue();

        // Fall back to placeholder if not available
        if (unifiedDiff == null || unifiedDiff.isEmpty()) {
            unifiedDiff = "// Unified diff not available for " + file.getPath();
        }

        highlightUnifiedDiff(unifiedPane, unifiedDiff);
    }

    private String generateSampleContent(ReviewFile file, Commit commit, boolean isOld) {
        // This is a placeholder - in a real app, you'd fetch actual file content from Git
        StringBuilder sb = new StringBuilder();
        sb.append("// ").append(file.getPath()).append("\n");
        sb.append("// Commit: ").append(commit.getShortHash()).append("\n");
        sb.append("\n");

        if (file.getChangeType() == FileChangeType.ADDED && isOld) {
            sb.append("// File does not exist in this commit\n");
        } else if (file.getChangeType() == FileChangeType.DELETED && !isOld) {
            sb.append("// File was deleted\n");
        } else {
            // Initial section - unchanged
            sb.append("public class Example {\n");
            sb.append("    private String name;\n");
            sb.append("    private int age;\n");
            sb.append("    \n");
            sb.append("    public Example(String name) {\n");
            sb.append("        this.name = name;\n");
            sb.append("    }\n");
            sb.append("    \n");

            // MIDDLE SECTION - Different for old vs new version
            if (isOld) {
                // OLD VERSION - Content that will be removed
                sb.append("    // Configuration section (WILL BE REMOVED)\n");
                sb.append("    private static final String CONFIG_PATH = \"/etc/config\";\n");
                sb.append("    private static final int MAX_RETRIES = 3;\n");
                sb.append("    private static final long TIMEOUT_MS = 5000;\n");
                sb.append("    \n");
                sb.append("    public void updateConfig() {  // DELETED METHOD\n");
                sb.append("        System.out.println(\"Updating config\");\n");
                sb.append("    }\n");
                sb.append("    \n");
            } else {
                // NEW VERSION - New content added
                sb.append("    // Logging section (NEW)\n");
                sb.append("    private static final Logger logger = LoggerFactory.getLogger(Example.class);\n");
                sb.append("    private static final String LOG_LEVEL = \"INFO\";\n");
                sb.append("    \n");
                sb.append("    // Authentication section (NEW)\n");
                sb.append("    private AuthProvider authProvider;  // NEW FIELD\n");
                sb.append("    private boolean isAuthenticated = false;  // NEW FIELD\n");
                sb.append("    \n");
            }

            // Final section - unchanged
            sb.append("    public String getName() {\n");
            sb.append("        return name;\n");
            sb.append("    }\n");
            sb.append("    \n");
            sb.append("    public int getAge() {\n");
            sb.append("        return age;\n");
            sb.append("    }\n");
            sb.append("    \n");

            if (isOld) {
                sb.append("    public void processRequest() {  // WILL BE MODIFIED\n");
                sb.append("        // Old implementation\n");
                sb.append("        String data = readData();\n");
                sb.append("    }\n");
            } else {
                sb.append("    public void processRequest() {  // MODIFIED METHOD\n");
                sb.append("        // New implementation with authentication\n");
                sb.append("        if (!isAuthenticated) return;  // NEW\n");
                sb.append("        String data = readData();\n");
                sb.append("        logger.info(\"Processing request\");  // NEW\n");
                sb.append("    }\n");
            }

            sb.append("}\n");
        }

        return sb.toString();
    }

    @SuppressWarnings({"unused", "UnusedParameters"})
    private String generateUnifiedDiff(ReviewFile file, Commit _startCommit, Commit _endCommit) {
        return "--- a/" + file.getPath() + "\n" +
                "+++ b/" + file.getPath() + "\n" +
                "@@ -1,25 +1,30 @@\n" +
                " public class Example {\n" +
                "     private String name;\n" +
                "     private int age;\n" +
                "     \n" +
                "     public Example(String name) {\n" +
                "         this.name = name;\n" +
                "     }\n" +
                "     \n" +
                "-    // Configuration section (WILL BE REMOVED)\n" +
                "-    private static final String CONFIG_PATH = \"/etc/config\";\n" +
                "-    private static final int MAX_RETRIES = 3;\n" +
                "-    private static final long TIMEOUT_MS = 5000;\n" +
                "-    \n" +
                "-    public void updateConfig() {  // DELETED METHOD\n" +
                "-        System.out.println(\"Updating config\");\n" +
                "-    }\n" +
                "-    \n" +
                "+    // Logging section (NEW)\n" +
                "+    private static final Logger logger = LoggerFactory.getLogger(Example.class);\n" +
                "+    private static final String LOG_LEVEL = \"INFO\";\n" +
                "+    \n" +
                "+    // Authentication section (NEW)\n" +
                "+    private AuthProvider authProvider;  // NEW FIELD\n" +
                "+    private boolean isAuthenticated = false;  // NEW FIELD\n" +
                "+    \n" +
                "     public String getName() {\n" +
                "         return name;\n" +
                "     }\n" +
                "     \n" +
                "     public int getAge() {\n" +
                "         return age;\n" +
                "     }\n" +
                "     \n" +
                "-    public void processRequest() {  // WILL BE MODIFIED\n" +
                "-        // Old implementation\n" +
                "-        String data = readData();\n" +
                "+    public void processRequest() {  // MODIFIED METHOD\n" +
                "+        // New implementation with authentication\n" +
                "+        if (!isAuthenticated) return;  // NEW\n" +
                "+        String data = readData();\n" +
                "+        logger.info(\"Processing request\");  // NEW\n" +
                "     }\n" +
                " }\n";
    }

    private void highlightDiffWithInlineChanges(LineNumberedTextPane leftPane, LineNumberedTextPane rightPane,
                                                 String beforeContent, String afterContent) {
        // Set text in both panes
        leftPane.setText(beforeContent);
        rightPane.setText(afterContent);

        Theme theme = themeManager.getCurrentTheme();
        JTextPane leftTextPane = leftPane.getTextPane();
        JTextPane rightTextPane = rightPane.getTextPane();

        StyledDocument leftDoc = leftTextPane.getStyledDocument();
        StyledDocument rightDoc = rightTextPane.getStyledDocument();

        // Create styles - set both foreground (theme) and background (highlight)
        // because setCharacterAttributes with replace=true wipes all attributes
        Style removedStyle = leftTextPane.addStyle("removed", null);
        StyleConstants.setForeground(removedStyle, theme.getForegroundColor());
        StyleConstants.setBackground(removedStyle, theme.getRemovedLineColor());

        Style addedStyle = rightTextPane.addStyle("added", null);
        StyleConstants.setForeground(addedStyle, theme.getForegroundColor());
        StyleConstants.setBackground(addedStyle, theme.getAddedLineColor());

        Style defaultStyle = leftTextPane.addStyle("default", null);
        StyleConstants.setForeground(defaultStyle, theme.getForegroundColor());

        Style defaultStyleRight = rightTextPane.addStyle("default", null);
        StyleConstants.setForeground(defaultStyleRight, theme.getForegroundColor());

        // Split into lines and compare
        String[] beforeLines = beforeContent.split("\n", -1);
        String[] afterLines = afterContent.split("\n", -1);

        int beforeOffset = 0;
        int afterOffset = 0;

        int maxLines = Math.max(beforeLines.length, afterLines.length);
        for (int i = 0; i < maxLines; i++) {
            String beforeLine = i < beforeLines.length ? beforeLines[i] : "";
            String afterLine = i < afterLines.length ? afterLines[i] : "";

            int beforeLineLength = beforeLine.length() + 1;
            int afterLineLength = afterLine.length() + 1;

            // Apply default style first
            if (beforeOffset + beforeLineLength <= leftDoc.getLength()) {
                leftDoc.setCharacterAttributes(beforeOffset, beforeLineLength, defaultStyle, true);
            }
            if (afterOffset + afterLineLength <= rightDoc.getLength()) {
                rightDoc.setCharacterAttributes(afterOffset, afterLineLength, defaultStyleRight, true);
            }

            // Find and highlight differences within the line
            if (!beforeLine.equals(afterLine)) {
                // Find common prefix
                int commonPrefix = 0;
                int minLen = Math.min(beforeLine.length(), afterLine.length());
                while (commonPrefix < minLen && beforeLine.charAt(commonPrefix) == afterLine.charAt(commonPrefix)) {
                    commonPrefix++;
                }

                // Find common suffix
                int commonSuffix = 0;
                while (commonSuffix < minLen - commonPrefix &&
                       beforeLine.charAt(beforeLine.length() - 1 - commonSuffix) ==
                       afterLine.charAt(afterLine.length() - 1 - commonSuffix)) {
                    commonSuffix++;
                }

                // Highlight the differences
                if (commonPrefix < beforeLine.length() - commonSuffix) {
                    int diffLength = beforeLine.length() - commonPrefix - commonSuffix;
                    leftDoc.setCharacterAttributes(beforeOffset + commonPrefix, diffLength, removedStyle, true);
                }

                if (commonPrefix < afterLine.length() - commonSuffix) {
                    int diffLength = afterLine.length() - commonPrefix - commonSuffix;
                    rightDoc.setCharacterAttributes(afterOffset + commonPrefix, diffLength, addedStyle, true);
                }
            }

            beforeOffset += beforeLineLength;
            afterOffset += afterLineLength;
        }
    }

    private void highlightUnifiedDiff(LineNumberedTextPane pane, String unifiedDiff) {
        pane.setText(unifiedDiff);

        Theme theme = themeManager.getCurrentTheme();
        JTextPane textPane = pane.getTextPane();
        StyledDocument doc = textPane.getStyledDocument();

        // Create styles - set both foreground (theme) and background (highlight)
        // because setCharacterAttributes with replace=true wipes all attributes
        Style addedStyle = textPane.addStyle("added", null);
        StyleConstants.setForeground(addedStyle, theme.getForegroundColor());
        StyleConstants.setBackground(addedStyle, theme.getAddedLineColor());

        Style removedStyle = textPane.addStyle("removed", null);
        StyleConstants.setForeground(removedStyle, theme.getForegroundColor());
        StyleConstants.setBackground(removedStyle, theme.getRemovedLineColor());

        Style defaultStyle = textPane.addStyle("default", null);
        StyleConstants.setForeground(defaultStyle, theme.getForegroundColor());

        // Apply styles based on line prefixes
        String[] lines = unifiedDiff.split("\n");
        int offset = 0;
        int lineNumber = 1;
        for (String line : lines) {
            int lineLength = line.length() + 1; // +1 for newline

            if (line.startsWith("+") && !line.startsWith("+++")) {
                doc.setCharacterAttributes(offset, lineLength, addedStyle, true);
                pane.markLineAdded(lineNumber);
            } else if (line.startsWith("-") && !line.startsWith("---")) {
                doc.setCharacterAttributes(offset, lineLength, removedStyle, true);
                pane.markLineRemoved(lineNumber);
            } else {
                doc.setCharacterAttributes(offset, lineLength, defaultStyle, true);
            }

            offset += lineLength;
            lineNumber++;
        }
    }

    public void clear() {
        leftPane.setText("");
        rightPane.setText("");
        unifiedPane.setText("");
        currentFile = null;
    }


    public void setOnLineDoubleClickListener(java.util.function.Consumer<Integer> listener) {
        leftPane.setOnLineDoubleClickListener(listener);
        rightPane.setOnLineDoubleClickListener(listener);
        unifiedPane.setOnLineDoubleClickListener(listener);
    }

    public void setCommentsForCurrentFile(java.util.List<ReviewComment> comments) {
        leftPane.setComments(comments);
        rightPane.setComments(comments);
        unifiedPane.setComments(comments);
    }

    @Override
    public void paint(Graphics g) {
        if (currentFile != null && lastRenderedTheme != themeManager.getCurrentTheme()) {
            showDiff(currentFile, startCommit, endCommit);
        }
        super.paint(g);
    }
}

package com.kalynx.serverlessreviewtool.ui.review;

